// Discovery Karaoke Prevention Engine — data.js v2.1
// Generated: 2026-04-16 | 69 methods | 11 tools | 13 patterns
// DO NOT EDIT — regenerate with tools/parse_data.py
const DATA = {"schema":{"cat":{"gen":"Generative","eval":"Evaluative","exp":"Experimentation","ana":"Analytics","sf":"Strategic Framing","syn":"Synthesis","col":"Collaborative","com":"Compliance"},"stage":{"E":"Explore","Va":"Validate","O":"Optimize"},"tier":{"core":"Core","ext":"Extended","spec":"Specialist"},"eff":{"low":"Low","lm":"Low-Medium","med":"Medium","mh":"Medium-High","high":"High"},"cx":{"s":"Simple","sm":"Simple-Moderate","m":"Moderate","mc":"Moderate-Complex","c":"Complex"},"ts":{"solo":"Solo","sm":"Small (2-5)","xfn":"Cross-functional (5+)"},"cs":{"start":"Startup","scale":"Scaleup","ent":"Enterprise","any":"Any"},"tn":{"fast":"Hours / Days","short":"1-2 weeks","med":"2-4 weeks","long":"Months+","on":"Ongoing"},"cost":{"t0":"Time-Only","low":"Low","med":"Medium","high":"High","vh":"Very High"},"ev":{"weak":"Weak","wm":"Weak-Moderate","mod":"Moderate","ms":"Moderate-Strong","str":"Strong","na":"N/A"},"evtype":{"beh":"Behavioral","sr":"Self-report","obs":"Observational","ej":"Expert Judgment","la":"Legal Assessment","meta":"Synthesis / Meta"},"risk":{"V":"Value/Desirability","U":"Usability","F":"Feasibility","Vi":"Viability","C":"Compliance & Ethics"}},"methods":[{"id":"M1","n":"User Interviews (Problem Discovery)","desc":"One-on-one conversations with users or potential users to understand their problems, needs, behaviors, and motivations in their own words. The foundational generative research method.","cat":"gen","tier":"core","r":["V"],"s":["E"],"eff":"med","cx":"m","ts":["solo","sm"],"cs":["any"],"t":"2-4 weeks","tn":"med","cost":"low","ev":"mod","evtype":"sr","out":"Research findings report with themes, user quotes, behavioral patterns, and opportunity areas. Often includes an affinity diagram.","how":["Define research questions – Write 3-5 specific questions you want to answer.","Create a discussion guide – 10-15 open-ended questions organized by theme.","Recruit participants – Screen for your target segment.","Conduct interviews – 30-60 minutes each.","Synthesize findings – Transcribe key quotes.","Share insights – Create a findings deck with themes, quotes, and implications."],"wtu":["You don't understand the problem space well enough to form hypotheses","You're entering a new market or user segment","Quantitative data shows WHAT is happening but not WHY"],"wnu":["You already have clear hypotheses and need to test them","The question is quantitative (\"how many?\" \"what percentage?\")","You're using interviews to validate what you already believe (confirmation bias trap)"],"kc":"","ai":"AI can draft discussion guides, transcribe recordings, and cluster themes from transcripts.","orig":"Rooted in ethnographic and clinical interviewing traditions. Popularized in product context by Steve Portigal (Interviewing Users, 2013) and Rob Fitzpatrick (The Mom Test, 2013).","eu":false,"lt":false,"lr":false,"pre":[]},{"id":"M2","n":"Jobs-to-be-Done (JTBD) Interviews","desc":"Structured interviews focused on the \"job\" a user is trying to accomplish, exploring the circumstances, motivations, and desired outcomes that drive switching behavior. Goes beyond surface needs to underlying motivations.","cat":"gen","tier":"core","r":["V","Vi"],"s":["E"],"eff":"mh","cx":"c","ts":["sm"],"cs":["any"],"t":"3-6 weeks","tn":"long","cost":"low","ev":"ms","evtype":"sr","out":"Job stories, Forces of Progress diagrams, job opportunity ranking, and strategic recommendations for product/market fit.","how":["Identify the switching moment – Find users who recently adopted, switched to, or abandoned a product/solution.","Conduct the Switch Interview – Use the Forces of Progress framework: Push (frustration with current), Pull (attraction of new), Anxiety (fear of change), Habit (comfort with status quo).","Map the job story – \"When [situation], I want to [motivation], so I can [expected outcome].\" Identify functional, emotional, and social dimensions of the job.","Cluster jobs – Group interviews by common jobs.","Prioritize jobs – Rank jobs by prevalence across interviews and severity of the push/pull forces.","Translate to product strategy – Map high-opportunity jobs to potential features, positioning, or new products."],"wtu":["You need to understand WHY users switch (or don't switch) to your product","You're defining or repositioning a product category","Feature-based research isn't revealing meaningful insights"],"wnu":["You need quick tactical input on UI/UX details","The product category is well-established and you're optimizing, not innovating","You don't have access to recent switchers (the technique requires people who recently made a change)"],"kc":"","ai":"AI can help analyze interview transcripts for Forces of Progress patterns and draft initial job stories for researcher validation.","orig":"Clayton Christensen (Harvard Business School), further developed by Bob Moesta and Chris Spiek at The Re-Wired Group. Switch Interview technique from Moesta & Spiek.","eu":false,"lt":false,"lr":false,"pre":[]},{"id":"M3","n":"Contextual Inquiry","desc":"Observing and interviewing users in their actual work or life context (home, office, field) while they perform real tasks. Reveals tacit knowledge, workarounds, and environmental factors that users can't or won't articulate in a lab setting.","cat":"gen","tier":"core","r":["V","U"],"s":["E"],"eff":"high","cx":"c","ts":["sm"],"cs":["scale","ent"],"t":"3-6 weeks","tn":"long","cost":"med","ev":"str","evtype":"obs","out":"Work models (flow, sequence, artifact, cultural, physical), affinity wall, design insights, and personas grounded in observed behavior.","how":["Plan the inquiry – Define what activities/tasks to observe.","Establish the master/apprentice model – Position yourself as apprentice learning from the user (the master).","Observe and interview simultaneously – Watch the user work.","Document artifacts – Photograph the environment, tools, sticky notes, whiteboards, workarounds.","Build interpretation notes – After each session, write up key observations, surprises, breakdowns, and workarounds within 24 hours.","Create work models – Synthesize across sessions into flow models, sequence models, artifact models, cultural models, and physical models."],"wtu":["Users operate in complex, specialized environments (hospitals, warehouses, factories, trading floors)","You suspect users have workarounds or tacit knowledge they can't articulate","Previous interview-only research failed to reveal actionable insights"],"wnu":["The activity is purely digital and synchronous remote observation is impractical","You have time or budget constraints that prevent field visits","Privacy or security restrictions prevent on-site observation"],"kc":"","ai":"AI can transcribe field recordings and help organize interpretation notes, but cannot replace the in-person observation itself.","orig":"Hugh Beyer and Karen Holtzblatt, developed at Digital Equipment Corporation in the 1980s.","eu":false,"lt":false,"lr":false,"pre":[]},{"id":"M4","n":"Ethnographic Research","desc":"Deep immersive research where researchers spend extended time in the user's environment, culture, or community to understand behaviors, values, and social dynamics. Goes beyond task observation to cultural understanding.","cat":"gen","tier":"ext","r":["V"],"s":["E"],"eff":"high","cx":"c","ts":["sm"],"cs":["ent"],"t":"4-12 weeks","tn":"long","cost":"high","ev":"str","evtype":"obs","out":"Cultural insights report, ethnographic narratives, personas, design principles, and strategic frameworks grounded in deep cultural understanding.","how":["Define the cultural question – What do you need to understand about people's lives, values, or practices that standard research can't reveal?.","Gain access and build trust – Enter the community or environment.","Immerse and observe – Participate in daily activities.","Maintain a field journal – Record daily observations, reflections, and emerging patterns.","Triangulate data – Cross-reference observations with interviews, artifacts, and secondary sources.","Synthesize into cultural insights – Create narratives, cultural frameworks, and design implications."],"wtu":["You're designing for an unfamiliar culture, community, or context","Previous research methods have failed to explain user behavior","You need to understand the emotional and social dimensions of product use"],"wnu":["You need quick answers for an upcoming sprint","The target users are easily accessible and well-understood","Budget and timeline don't allow for immersive research"],"kc":"","ai":"AI can assist with field note analysis and pattern identification across large volumes of ethnographic data, but cannot conduct immersive observation.","orig":"Rooted in cultural anthropology (Bronisław Malinowski, 1920s). Applied to design by IDEO, Doblin Group, and Jan Chipchase.","eu":false,"lt":false,"lr":false,"pre":[]},{"id":"M5","n":"Diary Studies","desc":"Participants self-report their experiences, behaviors, and emotions over an extended period (days to weeks) in their natural context. Captures longitudinal data about real-world behavior that single-session research misses.","cat":"gen","tier":"ext","r":["V","U"],"s":["E","Va"],"eff":"mh","cx":"m","ts":["sm"],"cs":["any"],"t":"2-6 weeks","tn":"med","cost":"low","ev":"ms","evtype":"sr","out":"Longitudinal experience maps, behavior pattern analysis, trigger-behavior-outcome chains, and rich contextual data about real-world product use.","how":["Design the diary protocol – Define what participants should report, when, and how.","Recruit and onboard participants – Select 10-15 participants.","Manage the study period – Send reminders.","Conduct follow-up interviews – After the diary period, interview participants to debrief.","Analyze longitudinal patterns – Look for patterns over time: frequency, triggers, emotional arcs, behavior changes, abandoned habits.","Map the experience timeline – Create a longitudinal experience map showing how needs, behaviors, and satisfaction change over the study period."],"wtu":["Behavior changes over time (onboarding, habit formation, seasonal patterns)","You need to capture in-the-moment experiences that users forget in retrospective interviews","You're studying infrequent but important events (e.g., filing taxes, booking travel)"],"wnu":["You need results in less than 2 weeks","Participant burden is too high for your audience (executives, patients)","The behavior you're studying happens in a single session"],"kc":"","ai":"AI can analyze diary entries at scale, detect sentiment trends over time, and flag notable patterns for researcher follow-up.","orig":"Rooted in psychology's Experience Sampling Method (Csikszentmihalyi & Larson, 1987), a signal-contingent or time-based sampling approach. UX diary studies are a broader family: participants report at natural trigger moments or defined intervals, with more flexible format and cadence than strict ESM. Applied to UX by researchers at Microsoft, Google, and academic HCI labs.","eu":false,"lt":false,"lr":false,"pre":[]},{"id":"M6","n":"Support Ticket Analysis","desc":"Systematic analysis of customer support tickets, help desk logs, and complaint records to identify recurring problems, pain points, and unmet needs directly from user-initiated feedback.","cat":"gen","tier":"core","r":["V","U"],"s":["E","O"],"eff":"lm","cx":"s","ts":["solo"],"cs":["any"],"t":"2-5 days","tn":"fast","cost":"t0","ev":"mod","evtype":"sr","out":"Categorized issue taxonomy, frequency analysis, top-10 pain points ranked by impact, and product opportunity recommendations.","how":["Export ticket data – Pull 3-6 months of support tickets from your help desk system.","Categorize and tag – Create a taxonomy of issue types.","Quantify frequency and impact – Count tickets per category.","Identify root causes – For the top issues, read individual tickets to understand the underlying problem.","Map to product opportunities – Connect support themes to product backlog items or new opportunities."],"wtu":["You have an existing product with a support channel and want to identify pain points","You need to prioritize bug fixes or UX improvements based on actual user impact","You want to complement other research with naturally occurring user feedback"],"wnu":["You don't have a product yet (no tickets to analyze)","Your support data is too noisy or poorly categorized to be useful","You're looking for new opportunities (support tickets reflect known problems, not unmet needs)","You're trying to understand root causes without follow-up (tickets show symptoms, not underlying motivations—pair with interviews to go deeper)"],"kc":"","ai":"AI excels here—can categorize tickets, extract themes, detect sentiment, and identify emerging trends across thousands of tickets in minutes.","orig":"Voice of the Customer (VoC) and service analytics practices. Used in product discovery as a secondary signal source alongside interviews and other generative methods.","eu":true,"lt":false,"lr":false,"pre":[]},{"id":"M7","n":"Forum/Community Analysis","desc":"Analyzing public discussions in forums, community sites, social media, app store reviews, and online communities to understand user needs, frustrations, and language from naturally occurring public discussion.","cat":"gen","tier":"core","r":["V"],"s":["E"],"eff":"low","cx":"s","ts":["solo"],"cs":["any"],"t":"1-3 days","tn":"fast","cost":"t0","ev":"wm","evtype":"obs","out":"Theme analysis, user language glossary, competitive perception map, unmet needs list, and representative user quotes.","how":["Identify relevant communities – Find where your target users discuss their problems: community forums, Q&A platforms, developer communities, social media groups, review sites, and app stores.","Collect posts and comments – Gather 50-200 relevant posts/threads.","Code for themes – Tag each post by problem type, user segment, emotional tone, and solution attempted.","Identify unmet needs – Look for recurring complaints, workarounds, and \"I wish…\" statements.","Synthesize and share – Create a brief report: top themes, representative quotes, and product implications."],"wtu":["You're exploring a new market and want to understand the landscape quickly and cheaply","You want to hear unfiltered user language (not influenced by your questions)","You want to understand competitive perceptions and pain points"],"wnu":["Your target users don't have active online communities","You need statistically representative data","You're in a regulated space where public discussion may not reflect actual usage"],"kc":"","ai":"AI is highly effective—can scrape, categorize, and summarize thousands of forum posts, detect sentiment trends, and extract common themes rapidly.","orig":"Netnography, coined by Robert Kozinets (2002). This entry describes the product-team adaptation—a lightweight passive scan of public communities—rather than full netnography, which can include deeper immersive participation and engagement.","eu":false,"lt":false,"lr":false,"pre":[]},{"id":"M8","n":"Sales Call Analysis","desc":"Reviewing recorded sales calls, demos, and prospect conversations to extract common objections, needs, buying triggers, and competitive intelligence directly from real purchase conversations.","cat":"gen","tier":"ext","r":["V","Vi"],"s":["E","Va"],"eff":"lm","cx":"s","ts":["solo"],"cs":["scale","ent"],"t":"1-3 days","tn":"fast","cost":"t0","ev":"mod","evtype":"obs","out":"Objection matrix, competitive intelligence summary, buyer needs map, win/loss themes, and product prioritization input.","how":["Access call recordings – Get access to your conversation intelligence tool or call recordings.","Categorize calls – Tag by outcome (won/lost/stalled), deal size, buyer persona, and industry.","Extract objections and needs – Listen/read for: stated needs, objections, competitor mentions, feature requests, buying criteria, and emotional triggers.","Compare won vs.","Map to product decisions – Connect findings to feature priorities, positioning, and messaging."],"wtu":["You're a B2B product team that doesn't regularly hear from end users","You want to understand why deals are won, lost, or stalled","You need to align product development with actual buying criteria"],"wnu":["You're B2C without a sales team","Sales recordings don't exist or are too few to find patterns","The sales process is so standardized that calls don't reveal authentic prospect needs"],"kc":"","ai":"AI is excellent here – conversation intelligence platforms already do this natively. AI can extract objections, track competitor mentions, and identify winning talk patterns across hundreds of calls.","orig":"B2B sales enablement practices. Accelerated by conversation intelligence platforms (Gong, Chorus, Clari) in the 2010s.","eu":false,"lt":false,"lr":false,"pre":[]},{"id":"M9","n":"Stakeholder Interviews","desc":"Structured interviews with internal stakeholders (executives, sales, support, engineering, legal, compliance) to understand business goals, constraints, institutional knowledge, and cross-functional perspectives.","cat":"gen","tier":"core","r":["Vi","F","C"],"s":["E"],"eff":"lm","cx":"s","ts":["solo","sm"],"cs":["any"],"t":"1-2 weeks","tn":"short","cost":"t0","ev":"mod","evtype":"sr","out":"Stakeholder alignment matrix, business constraints document, risk inventory, and cross-functional requirements.","how":["Identify key stakeholders – Map who has relevant knowledge or decision authority: product leadership, engineering leads, sales leaders, support managers, legal/compliance, finance.","Prepare tailored guides – Create 8-12 questions per stakeholder type.","Conduct interviews – 30-45 minutes each.","Map alignment and gaps – Create a stakeholder alignment matrix: where do they agree? Where do they conflict? What blind spots exist?.","Synthesize business context – Document the business constraints, success metrics, risk tolerance, and organizational dynamics that will shape your product decisions."],"wtu":["Starting a new initiative and need to understand business context and constraints","Cross-functional alignment is weak and you need to surface hidden assumptions","You need to assess feasibility, viability, or compliance risks from domain experts"],"wnu":["You're using stakeholder opinions as a substitute for user research (stakeholders ≠ users)","Stakeholder landscape is too political and interviews may cause more conflict than clarity","The information you need is already documented in strategy docs or OKRs"],"kc":"","ai":"AI can help synthesize notes across multiple stakeholder interviews and identify alignment/conflict patterns.","orig":"Standard business analysis practice, common across consulting, service design, and product management. Referenced in product contexts by Cagan and in service design by the UK Government Digital Service.","eu":false,"lt":false,"lr":false,"pre":[]},{"id":"M10","n":"Focus Groups","desc":"Facilitated group discussion (6-10 participants) exploring attitudes, perceptions, and reactions to concepts, products, or ideas. Leverages group dynamics to surface diverse perspectives and social influences.","cat":"gen","tier":"ext","r":["V"],"s":["E","Va"],"eff":"mh","cx":"c","ts":["sm"],"cs":["any"],"t":"2-4 weeks","tn":"med","cost":"med","ev":"wm","evtype":"sr","out":"Thematic analysis with group consensus/divergence map, concept reaction summaries, and recommendations.","how":["Define objectives – What specific questions will the focus group answer? Focus groups are best for exploring attitudes, perceptions, and social dynamics.","Design the moderator guide – Create a 90-minute structured discussion guide with warm-up, core topics, activities (card sorting, concept reactions), and wrap-up.","Recruit participants – 6-10 per group, run 2-4 groups for pattern reliability.","Facilitate the session – Manage group dynamics.","Analyze group dynamics – Note where the group agreed/disagreed, who influenced whom, and what topics generated energy.","Report findings – Summarize themes, notable quotes, areas of consensus/divergence, and implications for product decisions."],"wtu":["You want to explore attitudes and perceptions in a social context","You need to understand how people influence each other's opinions about a category","You want to quickly explore reactions to multiple concepts or ideas"],"wnu":["You need to understand individual behavior (focus groups reveal attitudes, not actions)","Sensitive or private topics where group pressure inhibits honesty","You're treating focus group preferences as purchase intent (classic mistake—\"liking\" in a group ≠ buying)"],"kc":"","ai":"AI can transcribe and analyze multi-speaker recordings, identify dominant vs. quiet participants, and extract themes across multiple sessions.","orig":"Robert K. Merton's \"focused interview\" work in the 1940s is widely cited as a precursor. Modern focus group practice as a market research tool developed through the 1950s–70s and is related to but not identical with Merton's original method.","eu":false,"lt":false,"lr":false,"pre":[]},{"id":"M11","n":"Surveys (Problem Validation)","desc":"Structured questionnaires distributed to a large sample to quantify the prevalence, severity, and segmentation of problems identified through qualitative research. Measures how widespread a problem is.","cat":"gen","tier":"core","r":["V"],"s":["Va"],"eff":"lm","cx":"m","ts":["solo","sm"],"cs":["any"],"t":"1-3 weeks","tn":"med","cost":"low","ev":"ms","evtype":"sr","out":"Quantified problem severity, user segmentation, statistical validation of qualitative findings, and prioritized problem list.","how":["Ground in qualitative insights – NEVER write a survey before qualitative research.","Write clear questions – 10-20 questions max.","Pilot test – Send to 5-10 people first.","Distribute to target sample – Aim for 100-500+ responses for statistical power.","Analyze quantitatively – Calculate frequencies, cross-tabulations, and segments.","Triangulate with qualitative data – Compare survey results with interview findings."],"wtu":["You've done qualitative research and want to quantify how widespread a problem is","You need to segment users by problem severity or behavior","You want statistical evidence to support a product decision"],"wnu":["You haven't done qualitative research yet (you'll write the wrong questions)","The question requires nuance that closed-ended questions can't capture","You're surveying to avoid talking to users (the Survey Spray anti-pattern)"],"kc":"","ai":"AI can analyze open-ended responses, segment data, identify patterns, and generate cross-tabulations.","orig":"Social science survey methodology. Applied to product by Sean Ellis (\"How disappointed would you be?\" question) and Teresa Torres.","eu":false,"lt":false,"lr":false,"pre":["M1"]},{"id":"M12","n":"Surveys (Satisfaction – NPS/CSAT/CES)","desc":"Ongoing measurement of customer satisfaction (CSAT), loyalty (NPS – Net Promoter Score), and effort (CES – Customer Effort Score) to track product health, identify at-risk segments, and measure the impact of changes over time. Each metric suits different contexts; evidence does not support a universal best choice across industries or product types.","cat":"ana","tier":"core","r":["V","U","Vi"],"s":["O"],"eff":"low","cx":"s","ts":["solo"],"cs":["any"],"t":"Ongoing","tn":"on","cost":"low","ev":"mod","evtype":"sr","out":"NPS/CSAT scores over time, segment analysis, open-ended feedback themes, and churn risk indicators.","how":["Choose your metric – NPS (\"How likely are you to recommend…\" 0-10) for loyalty/advocacy.","Design the survey – Keep it to 2-3 questions: the score question + \"What's the primary reason for your score?\" (open-ended) + optional segmentation question.","Set trigger and frequency – Decide when to ask: post-interaction (CSAT), periodic (NPS quarterly), or event-based (after onboarding).","Deploy and collect – Use in-product modals, email, or SMS.","Analyze trends – Track scores over time.","Close the feedback loop – Follow up with detractors."],"wtu":["You need an ongoing pulse on customer satisfaction","You want to measure the impact of product changes over time","You need to identify at-risk customers for churn prevention"],"wnu":["You're using NPS as your sole discovery method (it tells you satisfaction, not what to build)","Your product is too new to have meaningful longitudinal data","You're treating NPS as a goal rather than a signal (Goodhart's Law risk)"],"kc":"","ai":"AI excels at analyzing open-ended NPS/CSAT responses at scale—theme extraction, sentiment analysis, and trend detection.","orig":"NPS created by Fred Reichheld and Bain & Company (2003). CSAT rooted in customer satisfaction research (1970s-80s).","eu":true,"lt":false,"lr":false,"pre":[]},{"id":"M13","n":"Card Sorting","desc":"Participants organize topics, labels, or content items into groups that make sense to them, revealing their mental models for information architecture. Open sorts let users create categories; closed sorts test existing categories.","cat":"eval","tier":"core","r":["U"],"s":["E","Va"],"eff":"lm","cx":"sm","ts":["solo","sm"],"cs":["any"],"t":"1-2 weeks","tn":"short","cost":"low","ev":"mod","evtype":"beh","out":"Similarity matrix, dendrograms, recommended category structure, and label recommendations.","how":["Prepare content items – Write 30-60 items (features, pages, topics) on cards.","Choose sort type – Open sort: users create and name their own groups (for exploration).","Run sessions – In-person (5-8 participants, observe and discuss) or remote (15-30+ participants using a card sorting tool).","Analyze results – Create a similarity matrix showing how often items were grouped together.","Derive information architecture – Translate clusters into navigation structure, category labels, and content hierarchy."],"wtu":["You're designing or redesigning navigation/information architecture","You want to understand how users think about your content/feature categories","You need to validate category labels and groupings"],"wnu":["You're testing task flows or interactions","Your IA is simple enough that best practices suffice (e.g., settings page)","You have fewer than 15 items to sort (too few to reveal patterns)"],"kc":"","ai":"AI can analyze card sort data, generate similarity matrices, and suggest optimal groupings based on co-occurrence patterns.","orig":"Related to sorting and construct-elicitation traditions in psychology (Kelly, 1955, and others). Applied to information architecture as a product practice by Donna Spencer and the Nielsen Norman Group.","eu":false,"lt":false,"lr":false,"pre":[]},{"id":"M14","n":"Tree Testing","desc":"Participants are given a text-only version of a site's hierarchy (no design) and asked to find specific items, testing whether the information architecture is intuitive without visual design influence.","cat":"eval","tier":"ext","r":["U"],"s":["Va"],"eff":"low","cx":"s","ts":["solo"],"cs":["any"],"t":"3-7 days","tn":"fast","cost":"low","ev":"ms","evtype":"beh","out":"Task success rates, first-click accuracy, path analysis (where users go wrong), and IA improvement recommendations.","how":["Create the tree – Build a text-based hierarchy of your navigation structure in a tree testing tool.","Write tasks – Create 8-12 task scenarios: \"Where would you go to [do X]?\" Tasks should cover key user goals across different sections.","Recruit participants – 50-100 participants is a common practical target (a useful heuristic, not a statistical floor).","Analyze success rates – For each task: % correct (found the right item), % incorrect, and % who gave up.","Iterate the tree – Investigate paths with notably low success rates (60% is a common practitioner threshold, not a universal standard)."],"wtu":["After card sorting, to validate the proposed IA","Before visual design, to test navigation without design bias","When redesigning navigation and need to compare structures"],"wnu":["You need to test visual design or interaction patterns","The IA is trivial (5 or fewer top-level items with obvious labels)","You're testing content quality, not findability"],"kc":"","ai":"AI can generate task scenarios from user stories and help analyze path data for common failure patterns.","orig":"Developed by Dave O'Brien at Optimal Workshop (mid-2000s) as a complement to card sorting.","eu":false,"lt":false,"lr":false,"pre":["M13"]},{"id":"M15","n":"Five-Second Test","desc":"Participants view a design or page for exactly 5 seconds, then answer questions about what they noticed, understood, and remember. Tests first impressions, visual hierarchy, and clarity of messaging.","cat":"eval","tier":"ext","r":["U","V"],"s":["Va"],"eff":"low","cx":"s","ts":["solo"],"cs":["any"],"t":"1-3 days","tn":"fast","cost":"t0","ev":"wm","evtype":"sr","out":"Recall accuracy scores, first impression themes, value proposition clarity rating, and design iteration recommendations.","how":["Select the design – Choose the page, screen, or design mockup to test.","Write recall questions – \"What is this page about?\", \"What do you remember?\", \"What action would you take?\", \"Who is this product for?\".","Run the test – Upload to a five-second test tool or run in person.","Analyze responses – Categorize open-ended answers.","Iterate – If <60% correctly identify the page purpose, the visual hierarchy or messaging needs work."],"wtu":["You want to test whether a landing page communicates its value proposition clearly","You're choosing between design directions for first impressions","You need quick, cheap validation of visual hierarchy and messaging"],"wnu":["You're testing complex interactions or workflows","The page requires reading/comprehension beyond first impressions","You need behavioral data, not recall data"],"kc":"","ai":"AI can categorize open-ended recall responses and identify patterns across participants faster than manual coding.","orig":"Developed by Christine Perfetti and Jared Spool at UIE (2005). Based on research showing users form impressions within seconds.","eu":false,"lt":false,"lr":false,"pre":[]},{"id":"M16","n":"Usability Testing (Moderated)","desc":"A facilitator guides participants through tasks on a product/prototype while observing their behavior, asking follow-up questions, and probing their thought process in real time. The gold standard for understanding usability issues.","cat":"eval","tier":"core","r":["U","V"],"s":["Va","O"],"eff":"med","cx":"m","ts":["sm"],"cs":["any"],"t":"1-3 weeks","tn":"med","cost":"low","ev":"str","evtype":"obs","out":"Prioritized usability issues list (severity × frequency), task success rates, think-aloud insights, and video highlight reel.","how":["Define test objectives – What specific questions about usability do you need to answer? Write 3-5 research questions.","Create a test plan – Write 5-8 realistic task scenarios.","Recruit participants – 5-8 per round (five is a common starting point for qualitative rounds; the right number depends on user group diversity and study goals).","Conduct sessions – 45-60 minutes each.","Analyze and prioritize findings – Rate issues by severity and frequency.","Report and iterate – Share findings with the team."],"wtu":["You're testing a new design, flow, or prototype before development","You need to understand WHY users struggle, not just WHERE (the think-aloud reveals causation)","Key user journeys need validation before launch"],"wnu":["You need quantitative metrics from large samples","The design is live and you can run A/B tests instead","You're testing value/desirability, not usability"],"kc":"","ai":"AI can transcribe sessions, tag usability issues by type, and create highlight reels—but a human facilitator remains essential for probing and adapting in real time.","orig":"Formalized by Jakob Nielsen and Tom Landauer (1993, \"A Mathematical Model of Usability Testing\"). Popularized by Steve Krug (Don't Make Me Think, 2000).","eu":false,"lt":false,"lr":false,"pre":[]},{"id":"M17","n":"Usability Testing (Unmoderated)","desc":"Participants complete tasks on a product/prototype independently, without a facilitator present. Recorded remotely at scale via platforms, providing task completion data and qualitative think-aloud recordings. Can support quantitative benchmarking when properly designed and sampled.","cat":"eval","tier":"core","r":["U"],"s":["Va","O"],"eff":"lm","cx":"sm","ts":["solo","sm"],"cs":["any"],"t":"3-7 days","tn":"fast","cost":"low","ev":"ms","evtype":"beh","out":"Quantitative usability metrics (success rates, time-on-task, SUS scores), issue categories, and recordings for review.","how":["Write task scenarios – Create 5-8 clear, unambiguous tasks.","Set up the test – Configure on your remote testing platform.","Launch and recruit – Platform recruits participants or use your own panel.","Analyze quantitatively – Task success rates, time on task, error rates, SUS/SEQ scores.","Review recordings selectively – Watch recordings of failed tasks to understand why.","Prioritize and report – Combine quant metrics with qualitative insights."],"wtu":["You need quantitative usability benchmarks (success rates, time-on-task)","You want to test with a larger sample than moderated testing allows","You need fast turnaround on usability feedback"],"wnu":["You need to probe WHY users struggle","The prototype requires explanation or setup (no facilitator to assist)","Tasks are complex or ambiguous (participants will get confused without help)"],"kc":"","ai":"AI can auto-tag usability issues from recordings, generate metrics dashboards, and flag the most problematic moments for human review.","orig":"Enabled by remote testing platforms (UserTesting.com founded 2007, TryMyUI, Lookback). Evolved from moderated testing to scale.","eu":false,"lt":false,"lr":false,"pre":[]},{"id":"M18","n":"Expert/Heuristic Review","desc":"UX experts evaluate a product against established usability principles (heuristics) to identify potential usability issues without testing with real users. Fast and cost-effective way to find obvious problems.","cat":"eval","tier":"ext","r":["U"],"s":["Va","O"],"eff":"low","cx":"m","ts":["solo"],"cs":["any"],"t":"1-3 days","tn":"fast","cost":"t0","ev":"wm","evtype":"ej","out":"Heuristic evaluation report with prioritized issues, severity ratings, screenshots, and recommendations.","how":["Select heuristics – Use Nielsen's 10 heuristics or a domain-specific set.","Define scope – Which screens, flows, or features to review? Prioritize key user journeys.","Independent review – Each expert evaluates independently (avoid groupthink).","Consolidate findings – Merge issues from all experts.","Prioritize – Create a prioritized issues list: critical issues (fix before launch), major (fix soon), minor (fix eventually), cosmetic (nice to fix).","Report – Present findings with screenshots, heuristic violated, severity, and recommendation."],"wtu":["You need fast, cheap usability feedback before user testing","Budget or time doesn't allow for user testing","You want to identify obvious issues so usability tests can focus on deeper problems"],"wnu":["You're using expert review as a REPLACEMENT for user testing (experts identify many issues users would find, but miss context-dependent and task-specific ones)","The product is in early concept stage (not enough to evaluate against heuristics)","You don't have access to UX expertise (non-experts applying heuristics produce unreliable results)"],"kc":"","ai":"AI can perform a preliminary heuristic check by analyzing screenshots and identifying common pattern violations, but cannot replace expert judgment for subtle issues.","orig":"Jakob Nielsen's 10 Usability Heuristics (1994). Also: Gerhardt-Powals' cognitive engineering principles and Weinschenk & Barker classification.","eu":false,"lt":false,"lr":false,"pre":[]},{"id":"M19","n":"Accessibility Audit","desc":"Systematic evaluation of a product against accessibility standards (WCAG 2.1/2.2, Section 508, EN 301 549) to ensure usability for people with disabilities. Combines automated scanning with manual expert testing.","cat":"eval","tier":"core","r":["U","C"],"s":["Va","O"],"eff":"med","cx":"mc","ts":["solo","sm"],"cs":["any"],"t":"1-3 weeks","tn":"med","cost":"low","ev":"str","evtype":"ej","out":"WCAG conformance report (VPAT/ACR format), prioritized issues list, remediation plan with effort estimates.","how":["Run automated scans – Use an automated accessibility scanner to identify violations (WCAG 2.1 AA).","Manual keyboard testing – Navigate the entire product using only a keyboard.","Screen reader testing – Test with major screen readers on target platforms.","Check WCAG criteria – Systematically evaluate against WCAG 2.2 Level AA success criteria.","Test with assistive technology users – If possible, include people with disabilities in testing.","Create remediation plan – Prioritize by impact (how many users affected) and severity (blocker vs."],"wtu":["Legal compliance requirements (ADA, Section 508, EAA, EN 301 549)","You're launching a new product or major redesign","You've received accessibility complaints from users"],"wnu":["As a checkbox exercise without commitment to fixing findings (wastes time and money)","For internal tools with no external compliance requirements (still good practice, but lower priority)","When you think automated tools alone are sufficient (they catch only part of the problem space—many issues require manual keyboard, screen reader, and assistive technology testing)"],"kc":"","ai":"AI can assist with automated scanning and generate remediation suggestions, but manual testing with assistive technologies remains irreplaceable.","orig":"Web Content Accessibility Guidelines (WCAG) developed by W3C Web Accessibility Initiative, first published 1999, current version WCAG 2.2 (2023).","eu":false,"lt":false,"lr":false,"pre":[]},{"id":"M20","n":"A/B Testing","desc":"Randomly splitting users between two (or more) versions of a page, feature, or experience and measuring which performs better against a defined metric. The gold standard for causal evidence in optimization.","cat":"exp","tier":"core","r":["V","U","Vi"],"s":["Va","O"],"eff":"med","cx":"mc","ts":["sm"],"cs":["scale","ent"],"t":"2-6 weeks","tn":"med","cost":"low","ev":"str","evtype":"beh","out":"Statistical analysis with confidence intervals, lift estimates, segment breakdowns, and go/no-go decision with supporting evidence.","how":["Form a clear hypothesis – \"Changing [X] from [current] to [variant] will improve [metric] by [expected lift] because [rationale].\" No hypothesis = no experiment.","Calculate sample size – Use a power calculator.","Build and QA variants – Implement control and treatment.","Run the experiment – Let it run for the calculated duration.","Analyze results – Check for statistical significance (p-value), practical significance (is the lift meaningful?), and segment-level effects.","Make a decision – Ship the winner, iterate, or investigate."],"wtu":["You have enough traffic for a properly powered test (required sample size depends on baseline rate, minimum detectable effect, and variance—use a power calculator, not a fixed rule)","You want causal evidence that a change improves a metric","You're optimizing an existing experience (not testing completely new products)"],"wnu":["Traffic is too low for statistical significance","You're testing fundamentally different products, not variations","The change is obviously needed (e.g., fixing a broken button—just fix it, don't experiment)"],"kc":"","ai":"AI can suggest experiment designs, detect anomalies during runs, and perform automated segment analysis—but humans must define the hypothesis and interpret business implications.","orig":"Roots in agricultural experimentation (Ronald Fisher, 1920s). Applied to web optimization by Google (2000) and popularized by Kohavi, Tang & Xu.","eu":true,"lt":true,"lr":false,"pre":[]},{"id":"M21","n":"Multivariate Testing","desc":"Testing multiple variables simultaneously (e.g., headline + image + CTA button) to understand both individual and interaction effects. Finds the optimal combination of elements rather than testing one change at a time.","cat":"exp","tier":"ext","r":["V","U"],"s":["O"],"eff":"high","cx":"c","ts":["sm"],"cs":["ent"],"t":"4-8 weeks","tn":"long","cost":"low","ev":"str","evtype":"beh","out":"Main effect analysis per variable, interaction effects matrix, optimal combination recommendation, and lift estimates.","how":["Identify variables – Choose 2-4 page elements to test (headline, image, CTA, layout).","Create the test matrix – Full factorial: all possible combinations (e.g., 3 headlines × 2 images × 2 CTAs = 12 variants).","Calculate required traffic – Each variant needs sufficient traffic.","Build and launch – Implement all variants.","Run to significance – Typically 4-8 weeks.","Analyze main effects and interactions – Which individual elements matter most? Do any combinations create unexpected synergies or conflicts?."],"wtu":["You have very high traffic—enough to properly power all variant combinations given your baseline rate and minimum detectable effect (use a power calculator, not a fixed threshold)","You want to optimize multiple elements of a page simultaneously","You suspect interaction effects between elements (e.g., a certain image works better with a certain headline)"],"wnu":["Traffic is insufficient for the number of variants (most common mistake)","You're making a big directional change, not optimizing elements","You don't have data science support to analyze interaction effects properly"],"kc":"","ai":"AI can help design fractional factorial experiments, identify significant interactions, and recommend optimal combinations from complex result sets.","orig":"Extension of factorial experimental design (Ronald Fisher, 1920s). Applied to web optimization in the 2000s as platforms enabled it.","eu":true,"lt":true,"lr":false,"pre":[]},{"id":"M22","n":"Switchback Testing","desc":"Alternating between treatment and control conditions over time periods (e.g., hour by hour, day by day) for the same population, rather than splitting users. Used when user-level randomization isn't possible or when there are network effects.","cat":"exp","tier":"spec","r":["V","Vi"],"s":["Va","O"],"eff":"high","cx":"c","ts":["xfn"],"cs":["scale","ent"],"t":"2-6 weeks","tn":"med","cost":"low","ev":"ms","evtype":"beh","out":"Treatment effect estimates with temporal clustering accounted for, analysis of carryover effects, and business impact projections.","how":["Determine if switchback is needed – Is user-level randomization impossible due to network/marketplace effects? If yes, switchback is appropriate.","Design time windows – Define alternation periods.","Randomize time periods – Randomly assign each time window to treatment or control.","Implement and run – Build the switching mechanism.","Analyze with appropriate methods – Standard A/B test statistics don't apply."],"wtu":["Marketplace or platform products where one user's experience affects others","Pricing or algorithm changes that affect the entire market simultaneously","Logistics/delivery optimization where supply and demand are interconnected"],"wnu":["Standard user-level A/B testing is feasible (switchback is unnecessarily complex)","The treatment has lingering effects across time periods (carryover effects contaminate results)","You don't have data science capability to analyze clustered temporal data"],"kc":"","ai":"AI can help design optimal switching schedules and perform the complex statistical analysis required, including detecting carryover effects.","orig":"Developed to address situations where user-level randomization is invalid because treatment effects propagate across users or time—particularly common in marketplace, logistics, and platform contexts where supply and demand are interdependent.","eu":true,"lt":true,"lr":false,"pre":[]},{"id":"M23","n":"Fake Door / Painted Door Test","desc":"Presenting a feature, product, or option that doesn't actually exist yet (a button, menu item, or CTA) and measuring how many users click/engage with it. Measures real demand with zero build cost.","cat":"exp","tier":"core","r":["V"],"s":["Va"],"eff":"low","cx":"s","ts":["solo","sm"],"cs":["any"],"t":"1-2 weeks","tn":"short","cost":"t0","ev":"mod","evtype":"beh","out":"Click-through rate, demand signal (above/below threshold), interested user list (for follow-up research), and go/no-go recommendation.","how":["Identify the hypothesis – \"X% of users want [feature/product].\" Define the minimum click-through rate that would validate demand.","Create the fake door – Add a button, menu item, link, or CTA that represents the feature.","Design the reveal – When clicked, show a message: \"Thanks for your interest! This feature is coming soon.","Expose and measure – Run for 1-2 weeks or until you have statistically meaningful click data.","Analyze and decide – Compare click rate to your threshold."],"wtu":["You want to validate demand for a feature before building it","You need quantitative evidence to justify development investment","The feature is expensive to build and you want to de-risk before committing"],"wnu":["The feature is small enough that it's faster to just build it and measure usage","Your users will be frustrated or lose trust from fake features (carefully manage the reveal)","You need to understand WHY people want the feature, not just IF"],"kc":"","ai":"AI can help design the fake door copy and analyze click patterns by segment, but the method itself is fundamentally simple.","orig":"Lean Startup tradition (Eric Ries, 2011). \"Fake door,\" \"painted door,\" and \"feature fake\" are common practitioner terms for this technique—widely used but not a formally standardized method with a single canonical lineage.","eu":false,"lt":"conditional","lr":false,"pre":[]},{"id":"M24","n":"Landing Page Test","desc":"Creating a standalone landing page for a product or feature that doesn't exist yet, driving traffic to it, and measuring conversion (email signups, pre-registrations, purchases). Tests demand and value proposition messaging simultaneously.","cat":"exp","tier":"core","r":["V","Vi"],"s":["Va"],"eff":"lm","cx":"sm","ts":["solo","sm"],"cs":["start","scale"],"t":"1-3 weeks","tn":"med","cost":"low","ev":"mod","evtype":"beh","out":"Conversion rates by channel and variant, email waitlist, messaging effectiveness data, and demand validation.","how":["Define the value proposition – Write a clear, compelling description of what the product does and why it matters.","Build the landing page – Use a landing page builder or no-code tool.","Set up analytics – Track: page visits, scroll depth, CTA clicks, form completions, and conversion rate.","Drive traffic – Use paid ads, community channels, or targeted outreach.","Measure conversion – Calculate: visitor-to-signup rate.","Follow up with converters – Email or interview people who signed up."],"wtu":["You want to test if a concept has market demand before building","You're validating positioning and messaging alongside demand","You need to build an early waitlist for launch"],"wnu":["Your product is complex and can't be explained on a single page","You need to test usability or feasibility, not demand","You're in an enterprise B2B context where landing pages don't match the buying process"],"kc":"","ai":"AI can write landing page copy variants, analyze visitor behavior patterns, and help optimize conversion through headline/CTA suggestions.","orig":"Lean Startup methodology. Popularized by Buffer's transparent validation (Joel Gascoigne, 2011) and Dropbox's explainer video MVP.","eu":false,"lt":false,"lr":false,"pre":[]},{"id":"M26","n":"Concierge MVP","desc":"Manually delivering the product or service to real customers using human effort instead of technology. The core value proposition is real, but the delivery mechanism is manual. Tests whether the solution solves a real problem worth paying for.","cat":"exp","tier":"core","r":["V","Vi"],"s":["Va"],"eff":"mh","cx":"m","ts":["sm"],"cs":["start","scale"],"t":"2-6 weeks","tn":"med","cost":"low","ev":"str","evtype":"beh","out":"Retention data, willingness-to-pay validation, deep qualitative understanding of user needs, and feature prioritization based on actual usage.","how":["Define the core value proposition – What specific job are you doing for the user? Strip away all technology and describe the human service.","Recruit initial customers – Find 5-10 real target users who have the problem.","Deliver manually – Perform the service yourself.","Observe and iterate – Pay attention to what customers actually use vs.","Measure retention and willingness to pay – Do customers come back? Would they pay? How much? At what frequency?.","Identify automation opportunities – What parts of the manual process are most painful to deliver and most valued by customers? These are what you should build."],"wtu":["You need to validate both the problem and solution before investing in technology","The service is complex enough that you need to learn what users actually need","You want to test willingness to pay before building"],"wnu":["The value proposition requires technology that can't be replicated manually (e.g., real-time recommendations)","You can't deliver meaningful value with manual processes","The market requires scale to work (network effects, marketplace dynamics)"],"kc":"","ai":"AI can help automate parts of the manual delivery (drafting emails, generating recommendations), but the human touch is the point of this method.","orig":"Coined by Eric Ries (The Lean Startup, 2011). Classic example: Food on the Table (Manuel Rosso) where the founder personally created meal plans for each customer.","eu":false,"lt":false,"lr":false,"pre":[]},{"id":"M27","n":"Wizard of Oz","desc":"Users interact with what appears to be a working product, but behind the scenes, humans are manually performing the operations. Unlike concierge MVP, users typically interact through a product interface rather than directly with the team—and concealment is common, though not always required. Tests the complete user experience without building the technology.","cat":"exp","tier":"ext","r":["V","U"],"s":["Va"],"eff":"mh","cx":"c","ts":["sm"],"cs":["start","scale"],"t":"2-6 weeks","tn":"med","cost":"med","ev":"str","evtype":"beh","out":"User experience validation, behavioral data, edge cases discovered, automation requirements, and feasibility assessment.","how":["Build the facade – Create a realistic front-end (UI, chatbot interface, or product surface) that users interact with normally.","Set up the \"wizard\" operation – Define the manual process behind the scenes.","Recruit and onboard users – Get 5-20 real users to use the \"product.\" Concealment is common (users unaware the system is manually operated), but transparency about the simulation is also a valid approach depending on context and ethics.","Operate and observe – Run the manual operations.","Measure the experience – Satisfaction, task completion, repeat usage, and willingness to continue.","Debrief and plan – Analyze what you learned."],"wtu":["You want to test the full user experience including the interface, not just the value proposition","The technology is complex (AI, ML, algorithms) and you want to validate the concept before investing in it","You need to test natural-feeling interactions (chatbots, recommendations, search)"],"wnu":["Ethical concerns about deceiving users (consider disclosure or concierge MVP instead)","The manual operation can't match the expected response time (e.g., real-time applications)","You can build a working prototype faster than operating the facade manually"],"kc":"","ai":"AI can partially automate the \"wizard\" role (drafting responses for human review), reducing manual effort while maintaining the facade.","orig":"Named after the film (man behind the curtain). Term coined in HCI by Jeff Kelley (1983, Johns Hopkins University) for speech interface research.","eu":false,"lt":false,"lr":false,"pre":[]},{"id":"M28","n":"Paper Prototyping","desc":"Hand-drawn sketches of screens and UI elements used to test concepts, flows, and layouts with users before any digital design work. The fastest, cheapest way to explore design ideas and test with real users.","cat":"eval","tier":"core","r":["U"],"s":["E","Va"],"eff":"low","cx":"s","ts":["solo","sm"],"cs":["any"],"t":"1-3 days","tn":"fast","cost":"t0","ev":"mod","evtype":"obs","out":"Validated (or invalidated) design concepts, initial flow improvements, and key usability insights from early-stage testing.","how":["Sketch key screens – Draw the main screens on paper or index cards.","Prepare the interaction – Cut out movable elements (dropdown menus, dialog boxes, error messages).","Write task scenarios – \"You want to [goal].","Test with users – You act as the \"computer,\" swapping screens in response to user actions.","Iterate between sessions – Redraw screens that caused confusion."],"wtu":["Very early in the design process when you're exploring multiple concepts","You want to iterate rapidly without investing in digital tools","You want to test information architecture, content labels, basic flows, and broad interaction concepts—not visual design"],"wnu":["You need to test detailed interactions, animations, or responsive behavior","Users expect a realistic experience and paper would break immersion","The design is far enough along that digital prototyping is more efficient"],"kc":"","ai":"Limited—paper prototyping is inherently a physical, hands-on activity. AI can help generate wireframe sketches to print and test.","orig":"Popularized by Carolyn Snyder (2003). Used since the earliest days of HCI and interface design.","eu":false,"lt":false,"lr":false,"pre":[]},{"id":"M29","n":"Digital Prototyping","desc":"Creating interactive mockups using design and prototyping tools – including AI-assisted prototyping – that simulate the product experience without writing code. Ranges from clickable wireframes (low fidelity) to pixel-perfect interactive designs (high fidelity).","cat":"eval","tier":"core","r":["U","V"],"s":["E","Va"],"eff":"med","cx":"m","ts":["solo","sm"],"cs":["any"],"t":"3-10 days","tn":"fast","cost":"low","ev":"ms","evtype":"obs","out":"Interactive prototype, usability test results, validated design ready for development, and design specification.","how":["Define fidelity level – Low-fi (wireframes, grayscale, placeholder content) for early exploration.","Build key flows – Prototype the 3-5 most important user journeys.","Add interactions – Make it clickable: buttons link to screens, forms show states, navigation works.","Test with users – Run moderated or unmoderated usability tests using the prototype.","Iterate – Fix issues in the design tool."],"wtu":["You need to test interactions, flows, and visual design before building","Stakeholders need to \"see it\" before committing to development","You want to test with users at a higher fidelity than paper but without code"],"wnu":["You're testing value/demand, not usability","The prototype would take as long as building the real thing","You're spending weeks on pixel-perfect prototypes when wireframes would suffice (over-investing in fidelity)"],"kc":"","ai":"AI tools (Galileo AI, Uizard) can generate initial wireframes and layouts, accelerating the starting point. AI can also generate placeholder content.","orig":"Rooted in interactive prototyping practice and fidelity theory in HCI (Houde & Hill, 1997; Buxton, 2007). The core idea—matching prototype fidelity to the question being answered—predates modern tools. Contemporary digital tools (Figma, Axure, Framer) have lowered the cost and raised the ceiling of what teams can prototype without code.","eu":false,"lt":false,"lr":false,"pre":[]},{"id":"M31","n":"Design Sprint","desc":"A structured 5-day process for rapidly prototyping and testing ideas. Monday: map the problem. Tuesday: sketch solutions. Wednesday: decide. Thursday: prototype. Friday: test with real users (5 is a common sprint convention, not a fixed rule – the evidence comes from the Friday test, not the sprint itself). Compresses months of work into one week.","cat":"col","tier":"ext","r":["V","U","F"],"s":["E","Va"],"eff":"high","cx":"c","ts":["xfn"],"cs":["any"],"t":"5 days","tn":"fast","cost":"low","ev":"mod","evtype":"obs","out":"Tested prototype, user feedback from 5 sessions, validated/invalidated concept, and clear next steps (build/iterate/kill).","how":["Monday – Map – Define the challenge.","Tuesday – Sketch – Individual brainstorming.","Wednesday – Decide – Silent voting on sketches.","Thursday – Prototype – Build a realistic-looking prototype (design tool, slides, or even a physical facade).","Friday – Test – Run 5 one-on-one usability tests with real target users.","Post-sprint – Decide next steps – What did you learn? Build it? Iterate? Kill it? Run another sprint?."],"wtu":["Big, ambiguous challenges where the team doesn't know where to start","Cross-functional alignment is needed alongside solution exploration","You want to compress months of debate into one decisive week"],"wnu":["The question is small enough that a 2-hour assumption mapping would suffice","You already know what to build and need to test it","Team can't commit 5 full days (half-hearted sprints produce half-hearted results)"],"kc":"","ai":"AI can assist with research compilation for Monday, generate sketch variations for Tuesday, help write prototype content for Thursday, and analyze test recordings from Friday.","orig":"Developed by Jake Knapp at Google Ventures (GV), drawing on IDEO's design thinking and Lean Startup methodology.","eu":false,"lt":false,"lr":false,"pre":[]},{"id":"M44","n":"Spike Solution","desc":"A time-boxed technical investigation to answer a specific feasibility question. Throw-away code designed to learn, not to ship. The engineering equivalent of a discovery experiment.","cat":"exp","tier":"core","r":["F"],"s":["E","Va"],"eff":"lm","cx":"sm","ts":["solo","sm"],"cs":["any"],"t":"1-3 days","tn":"fast","cost":"t0","ev":"str","evtype":"ej","out":"Spike findings document: question asked, approach taken, answer found, implications for product/architecture decisions.","how":["Frame the question – Write one specific feasibility question: \"Can we integrate with X API in under 200ms?\" or \"Can our database handle 10M rows with this query pattern?\".","Set a timebox – 1-3 days maximum.","Build the minimum to answer – Build only what's needed to answer the question.","Document findings – What did you learn? What's possible? What's not? What are the constraints?.","Make the decision – Based on findings: proceed (feasible), modify approach (feasible with changes), or kill (not feasible).","Throw away the code – Spike code is NOT production code."],"wtu":["You have a specific technical uncertainty blocking a go/no-go decision","The team is debating feasibility without data","You need to estimate effort for a feature but the technology is unfamiliar"],"wnu":["The feasibility question is well-understood","You're using spikes to avoid committing to a decision (spike procrastination)","The \"spike\" keeps growing beyond the timebox"],"kc":"","ai":"AI can help write spike code faster, suggest technical approaches, and draft the findings document.","orig":"Extreme Programming (XP) methodology. Kent Beck introduced spikes as a way to reduce technical uncertainty.","eu":false,"lt":false,"lr":false,"pre":[]},{"id":"M45","n":"Proof of Concept (PoC)","desc":"A functional demonstration that a concept or approach is technically viable. More complete than a spike; focused on proving feasibility rather than user experience (in practice, the boundary with prototype can blur). Proves \"this can work\" before investing in full development.","cat":"exp","tier":"core","r":["F"],"s":["Va"],"eff":"mh","cx":"mc","ts":["sm"],"cs":["scale","ent"],"t":"1-4 weeks","tn":"med","cost":"med","ev":"str","evtype":"beh","out":"Working PoC demonstration, evaluation document with success criteria results, and go/no-go recommendation.","how":["Define success criteria – What must the PoC demonstrate to be considered successful? Write measurable criteria.","Scope ruthlessly – Only build what's needed to prove the concept.","Build the PoC – Functional but not production-ready.","Demonstrate to stakeholders – Show the PoC working.","Evaluate against criteria – Did it meet success criteria? Document what worked, what didn't, and what remains unknown.","Decide: proceed, pivot, or kill – Based on PoC results, decide whether to invest in full development."],"wtu":["A major technical decision hinges on whether an approach is viable","Stakeholders need to see something working before approving investment","You're evaluating a third-party technology or integration"],"wnu":["The concept is already proven (skip to prototyping or building)","You're using the PoC to delay a decision you could make with less effort","The PoC scope keeps expanding (it's becoming the product, not a proof)"],"kc":"","ai":"AI can accelerate PoC development by generating boilerplate code, suggesting architecture patterns, and drafting evaluation criteria.","orig":"Engineering and R&D practice, widely used in enterprise software sales and technical validation.","eu":false,"lt":false,"lr":false,"pre":[]},{"id":"M47","n":"Concept Testing","desc":"Presenting a product concept (not a working product) to potential users to gauge interest, comprehension, and perceived value. Tests the idea before building anything. Can use descriptions, storyboards, mockups, or videos.","cat":"eval","tier":"core","r":["V"],"s":["Va"],"eff":"lm","cx":"sm","ts":["solo","sm"],"cs":["any"],"t":"1-2 weeks","tn":"short","cost":"low","ev":"mod","evtype":"sr","out":"Concept test findings with comprehension scores, interest levels, quoted reactions, and go/iterate/kill recommendation.","how":["Create the concept artifact – Write a product description, create a storyboard, or build a simple mockup.","Define what you're testing – Value (do they want it?), comprehension (do they understand it?), or differentiation (is it better than alternatives?).","Recruit target users – 5-10 people for qualitative rounds; larger samples (50+) are appropriate when concept testing is done quantitatively with structured rating questions.","Present and observe – Show the concept.","Synthesize reactions – Map responses across comprehension, desire, and concerns.","Decide: refine, proceed, or pivot – Based on signal strength, either iterate the concept, move to prototyping, or abandon."],"wtu":["You have a product idea but want to validate interest before investing in development","You need quick directional signal on whether an idea resonates","You want to compare multiple concepts with the same audience"],"wnu":["You need behavioral evidence, not opinion","The concept is too abstract to present meaningfully","You're using positive reactions as definitive proof of demand (say vs. do gap)"],"kc":"","ai":"AI can generate concept descriptions, create storyboards, and analyze reaction patterns across participants.","orig":"Market research tradition. NN/g defines concept testing as an attitudinal method used early to determine whether users want or need a proposed product or service; applied in product discovery by Cagan and others.","eu":false,"lt":false,"lr":false,"pre":[]},{"id":"M48","n":"Pre-sales / Letter of Intent (LOI)","desc":"Getting prospective customers to commit resources (money, time, or a written letter of intent) before the product exists. Commitment level varies—from a non-binding LOI to prepayment or a signed purchase order—with stronger commitments providing stronger demand signals.","cat":"exp","tier":"ext","r":["V","Vi"],"s":["Va"],"eff":"mh","cx":"m","ts":["sm"],"cs":["start","scale"],"t":"2-8 weeks","tn":"med","cost":"low","ev":"str","evtype":"beh","out":"Pre-sales pipeline with commitment levels, signed LOIs, and demand assessment.","how":["Create a compelling product narrative – Describe the product, its value proposition, and timeline.","Identify target buyers – Who would buy this if it existed? Get to decision-makers, not just users.","Pitch the product – Present to 10-20 prospects.","Track commitment level – Verbal interest (weak), email confirmation (moderate), signed LOI (strong), pre-payment/deposit (strongest).","Set a threshold – Define what constitutes sufficient demand.","Decide based on commitments – Met threshold? Build."],"wtu":["You're considering a significant investment (new product, major feature, market entry)","You need to validate willingness to pay, not just interest","You're in B2B where pre-sales conversations are natural"],"wnu":["B2C mass market","You can't describe the product compellingly yet","You're using LOIs to delay building when demand is already proven"],"kc":"","ai":"AI can draft pitch decks, LOI templates, and follow-up emails. Can analyze CRM data to identify highest-probability prospects.","orig":"Enterprise sales practice and lean startup methodology. Eric Ries and Steve Blank emphasized pre-sales as demand validation.","eu":false,"lt":false,"lr":true,"pre":[]},{"id":"M49","n":"Crowdfunding Validation","desc":"Using crowdfunding platforms or internal equivalents to validate demand by collecting real pre-orders or pledges before building. Public, quantitative demand validation with real money. Equity crowdfunding extends this to B2B and investment-stage validation.","cat":"exp","tier":"spec","r":["V","Vi"],"s":["Va"],"eff":"high","cx":"c","ts":["sm","xfn"],"cs":["start"],"t":"4-12 weeks","tn":"long","cost":"med","ev":"str","evtype":"beh","out":"Campaign results with funding total, backer demographics, tier popularity, and demand assessment.","how":["Create campaign materials – Product video, detailed description, reward tiers, stretch goals.","Build a pre-launch audience – Email list, social following, PR outreach.","Set a realistic funding goal – Minimum viable amount.","Launch and manage – Actively manage the campaign: updates, backer communication, PR, social media.","Analyze results – Did you hit the goal? How fast? What tiers were most popular? What questions did backers ask?.","Fulfill or refund – If funded, you now have an obligation."],"wtu":["You're building a consumer/hardware product and need public demand validation","You want to simultaneously validate demand AND raise initial capital","You need external social proof for investor or stakeholder buy-in"],"wnu":["B2B enterprise products","Software-only products where a Landing Page test is faster and cheaper","You're not prepared to fulfill if the campaign succeeds"],"kc":"","ai":"AI can help write campaign copy, analyze comparable campaigns for pricing/tier strategy, and draft backer updates.","orig":"Crowdfunding platforms (Kickstarter founded 2009, Indiegogo 2008) created a natural demand validation mechanism.","eu":false,"lt":false,"lr":true,"pre":[]},{"id":"M53","n":"Kano Model Analysis","desc":"A customer satisfaction framework that classifies features into five categories: Must-be (expected), One-dimensional (more = better), Attractive (delighters), Indifferent, and Reverse. Reveals which features drive satisfaction vs. which merely prevent dissatisfaction.","cat":"eval","tier":"ext","r":["V"],"s":["Va"],"eff":"med","cx":"m","ts":["solo","sm"],"cs":["scale","ent"],"t":"2-4 weeks","tn":"med","cost":"low","ev":"mod","evtype":"sr","out":"Kano classification table, feature categorization diagram, and prioritization recommendations.","how":["Select features to evaluate – Choose 5-15 features or concepts.","Create Kano questionnaire – For each feature, ask two questions: functional (\"If this feature were present, how would you feel?\") and dysfunctional (\"If this feature were absent, how would you feel?\").","Distribute survey – Target 50-200 respondents from your user base or target market.","Classify features – Use the Kano evaluation table to map each functional/dysfunctional pair to a category: Must-be, One-dimensional, Attractive, Indifferent, or Reverse.","Visualize and prioritize – Plot features on the Kano diagram.","Apply to roadmap – Must-be gaps = urgent fixes."],"wtu":["You're prioritizing a feature backlog and need to distinguish between \"must have\" and \"nice to have\"","You want to understand which features will actually delight users vs. which are just expected","You're in a competitive market and need to identify differentiation opportunities"],"wnu":["You have too few respondents for meaningful analysis (30 is a rough practical starting point, not a statistical threshold—adequacy depends on number of features and variance in responses)","Features are too abstract for users to evaluate meaningfully","You're using it to justify not building must-be features (must-be features don't delight, but their absence creates dissatisfaction)"],"kc":"","ai":"AI can help design the Kano questionnaire, process survey responses, and generate the classification analysis.","orig":"Noriaki Kano, Tokyo University of Science (1984). Based on the dual nature of quality – presence of desirable attributes vs. absence of undesirable ones.","eu":false,"lt":false,"lr":false,"pre":[]},{"id":"M54","n":"Preference Testing","desc":"Presenting users with 2+ design or concept alternatives and asking them to choose their preference. Quick, quantitative signal on which direction resonates more. Often used for visual design, messaging, or feature framing.","cat":"eval","tier":"core","r":["V","U"],"s":["Va"],"eff":"low","cx":"s","ts":["solo","sm"],"cs":["any"],"t":"1-3 days","tn":"fast","cost":"low","ev":"wm","evtype":"sr","out":"Preference test results with win rates, qualitative rationale, and design recommendation.","how":["Create alternatives – 2-4 options to compare.","Define what you're testing – Preference (which do you like more?), clarity (which do you understand better?), or appeal (which would you click?).","Set up the test – Use a preference testing platform or a simple survey form.","Recruit participants – 20-50 people for directional signal, 100+ for statistical confidence.","Analyze results – Count preferences.","Apply learnings – Use preference data to inform the design direction."],"wtu":["You have 2+ viable options and need a quick signal on direction","Design debates are slowing down decision-making","You want quantitative backup for a design choice"],"wnu":["You're testing a single option","The options differ in functionality, not just presentation","You're using preference as a proxy for effectiveness (users may prefer a design that performs worse)"],"kc":"","ai":"AI can generate design variants, analyze qualitative feedback patterns, and suggest hypotheses for why one option was preferred.","orig":"Market research and advertising testing. Adapted for UX by tools like UsabilityHub (now Lyssna) and Maze.","eu":false,"lt":false,"lr":false,"pre":[]},{"id":"M55","n":"Cohort Analysis","desc":"Grouping users by a shared characteristic or time period (e.g., sign-up week, feature adoption date) and tracking their behavior over time. Reveals trends that aggregate metrics hide – like whether retention is improving for newer cohorts.","cat":"ana","tier":"ext","r":["V","Vi"],"s":["O"],"eff":"med","cx":"m","ts":["solo","sm"],"cs":["scale","ent"],"t":"1-3 days (setup) + ongoing monitoring","tn":"on","cost":"low","ev":"str","evtype":"beh","out":"Cohort analysis table/chart, trend identification, and recommendations for product or marketing changes.","how":["Define the cohort – By what attribute are you grouping users? Time-based is most common.","Define the metric – What behavior are you tracking over time? Retention, activation, revenue, feature usage.","Set up the analysis – Use your analytics platform or build a spreadsheet.","Visualize – Create a cohort table (heat map) showing how each cohort performs over time.","Identify patterns – Is retention improving for newer cohorts? Did a specific product change improve activation? Which acquisition channel produces best long-term users?.","Act on findings – Use cohort insights to prioritize: double down on what's working for the best cohorts, investigate what's different for the worst."],"wtu":["Aggregate metrics look flat but you suspect underlying trends (improving or declining)","You want to measure the impact of a product change on user behavior over time","You need to understand retention patterns beyond simple \"Day 1/7/30\" numbers"],"wnu":["You don't have enough users per cohort for meaningful analysis (50 is a common practical starting point, not a universal minimum—the right threshold depends on cohort metric variance and trends you're trying to detect)","You're looking for a one-time answer (cohort analysis is about trends over time)","You're using cohort data without understanding why cohorts differ"],"kc":"","ai":"AI can automate cohort segmentation, identify statistically significant differences between cohorts, and suggest hypotheses for observed patterns.","orig":"Statistical analysis tradition. Applied to product analytics by pioneers like Andrew Chen (Uber, a16z) and the Mixpanel/Amplitude analytics platforms.","eu":true,"lt":false,"lr":false,"pre":[]},{"id":"M56","n":"Funnel Analysis","desc":"Mapping the sequential steps users take toward a goal (sign-up, purchase, activation) and measuring conversion/drop-off at each step. Identifies exactly where users abandon and which steps need improvement.","cat":"ana","tier":"core","r":["V","U","Vi"],"s":["O"],"eff":"lm","cx":"sm","ts":["solo","sm"],"cs":["any"],"t":"1-3 days (setup) + ongoing monitoring","tn":"on","cost":"low","ev":"str","evtype":"beh","out":"Funnel visualization with conversion rates per step, identified drop-off points, and prioritized optimization recommendations.","how":["Define the funnel – What's the critical user journey? Sign-up → Onboarding → Activation → Retention → Revenue.","Instrument tracking – Ensure each step is tracked in your analytics.","Build the funnel visualization – Step 1 → Step 2 → Step 3, with conversion percentages between each step.","Identify the biggest drop-off – Where are you losing the most users? This is your highest-leverage optimization opportunity.","Diagnose the drop-off – WHY are users dropping off at that step? Use session recordings, heatmaps, or user interviews to understand.","Fix and measure – Address the drop-off cause, then re-measure the funnel."],"wtu":["You have a critical user journey and need to know where users abandon","Conversion rates are lower than expected and you need to find the bottleneck","You want to prioritize UX improvements by impact on the overall journey"],"wnu":["You don't have enough traffic for meaningful conversion rates (100 per step is a common practical guideline, not a statistical rule—required volume depends on expected conversion rates and the effect sizes you care about)","The user journey isn't sequential","You're over-optimizing micro-steps when the macro problem is product-market fit"],"kc":"","ai":"AI can identify unusual drop-off patterns, segment funnels by user type, and suggest optimization hypotheses based on comparable products.","orig":"Sales funnel concept (AIDA model, 1898). Applied to product analytics by web analytics platforms and growth teams.","eu":true,"lt":true,"lr":false,"pre":[]},{"id":"M57","n":"Feature Audit / Usage Analytics","desc":"Systematic analysis of how existing product features are actually used – frequency, depth, user segments, and adoption curves. Separates loved features from abandoned ones. Essential for informed pruning, investment, and roadmap decisions.","cat":"ana","tier":"core","r":["V","Vi"],"s":["O"],"eff":"med","cx":"m","ts":["solo","sm"],"cs":["scale","ent"],"t":"1-2 weeks","tn":"short","cost":"low","ev":"str","evtype":"beh","out":"Feature audit report with usage data, categorization (core/utility/niche/unused), and recommendations for each category.","how":["Inventory features – List all features in your product.","Define usage metrics – For each feature: DAU/MAU, frequency of use, time spent, adoption rate (% of users who use it at least once).","Pull usage data – Extract from your analytics platform.","Categorize features – High adoption + high frequency (core), high adoption + low frequency (utility), low adoption + high frequency (niche power), low adoption + low frequency (candidates for removal).","Investigate surprises – Why is that feature never used? Is it hidden, broken, or unnecessary? Why is that niche feature used daily by a small group?.","Make roadmap decisions – Invest in core features."],"wtu":["You're prioritizing the roadmap and want data-driven input on where to invest","Product complexity is growing and you need to identify candidates for simplification","You want to understand the gap between what's built and what's actually valued"],"wnu":["You're pre-launch with no usage data","You only have a few features (just look at the analytics directly)","You're using usage data alone without understanding WHY (low usage might mean the feature is hard to find, not unwanted)"],"kc":"","ai":"AI can automate feature categorization, identify unusual usage patterns, and generate hypotheses for why certain features are underused.","orig":"Product analytics practice. Enabled by tools like Pendo, Amplitude, Mixpanel, and Heap.","eu":true,"lt":false,"lr":false,"pre":[]},{"id":"M58","n":"Session Recording Analysis","desc":"Watching recordings of real user sessions to observe actual behavior – clicks, scrolls, hesitations, confusion, rage clicks. Reveals how users actually interact with a product in ways that analytics alone cannot show.","cat":"ana","tier":"core","r":["U"],"s":["O"],"eff":"lm","cx":"s","ts":["solo","sm"],"cs":["any"],"t":"1-5 days","tn":"fast","cost":"low","ev":"ms","evtype":"obs","out":"Session analysis report with observed patterns, frequency counts, specific issues identified, and prioritized fix recommendations.","how":["Define the focus area – Don't watch random sessions.","Set up recording – Configure your session recording tool.","Watch 20-50 sessions – Look for patterns: where do users pause, backtrack, click unexpectedly, or abandon? Note timestamps of interesting moments.","Code behaviors – Create a simple taxonomy: confusion (pauses, re-reads), frustration (rage clicks, rapid scrolling), abandonment (leaves mid-flow), success (completes goal).","Identify patterns – Which issues appear in 3+ sessions? These are systemic problems, not individual quirks.","Prioritize fixes – Rank by frequency × severity."],"wtu":["You know WHERE users drop off (from funnel analysis) but not WHY","You want to see how users actually interact with a new feature post-launch","You need to build empathy across the team for user struggles"],"wnu":["You don't have enough traffic (< 100 sessions per flow for meaningful patterns)","You're watching sessions without a specific hypothesis or focus (you'll waste hours)","You're using recordings instead of talking to users (recordings show what, not why)"],"kc":"","ai":"AI-powered session analysis tools can automatically detect rage clicks, dead clicks, and error patterns – reducing the need for manual session-by-session review.","orig":"Web analytics evolution. Tools like FullStory, Hotjar, and LogRocket made session recording accessible to product teams.","eu":true,"lt":false,"lr":true,"pre":[]},{"id":"M59","n":"Heatmap Analysis","desc":"Visual representation of aggregate user behavior on a page – where they click, how far they scroll. Shows interaction patterns at a glance. Complementary to session recordings but aggregate rather than individual.","cat":"ana","tier":"core","r":["U"],"s":["O"],"eff":"low","cx":"s","ts":["solo"],"cs":["any"],"t":"1-3 days","tn":"fast","cost":"low","ev":"mod","evtype":"beh","out":"Heatmap visuals (click, scroll, move) with annotated insights and design recommendations.","how":["Select pages to analyze – Focus on high-traffic pages or pages with known conversion issues.","Set up heatmap tracking – Install your heatmap tool.","Collect sufficient data – Need sufficient pageviews for reliable patterns – commonly cited starting points are 1,000+ for click heatmaps and 2,000+ for scroll maps, but the right threshold depends on the variance in your user population and the decisions you're making.","Analyze click heatmaps – Where are users clicking? Are they clicking non-clickable elements (false affordance)? Are they missing important CTAs?.","Analyze scroll heatmaps – How far do users scroll? If key content is below the fold and users don't scroll there, it's invisible.","Apply findings – Move important elements to high-attention zones."],"wtu":["You want a quick visual overview of how users interact with a page","You're optimizing page layout, CTA placement, or content hierarchy","You suspect users aren't seeing important content or are confused by the layout"],"wnu":["You need to understand user intent (heatmaps show where, not why","The page has very low traffic (unreliable data)","You're analyzing complex multi-step flows"],"kc":"","ai":"AI can automatically identify click clusters, dead zones, and anomalous interaction patterns from heatmap data.","orig":"Web analytics practice. Popularized by tools like Crazy Egg (founded by Neil Patel, 2005) and Hotjar (2014).","eu":true,"lt":true,"lr":true,"pre":[]},{"id":"M60","n":"Continuous Interviewing","desc":"A discipline of conducting regular, ongoing user interviews (typically weekly) as a continuous discovery habit rather than a project-based activity. Builds cumulative understanding over time and prevents the \"we talked to users 6 months ago\" trap.","cat":"gen","tier":"core","r":["V","U"],"s":["E","Va","O"],"eff":"med","cx":"m","ts":["sm"],"cs":["scale","ent"],"t":"Ongoing","tn":"on","cost":"low","ev":"mod","evtype":"sr","out":"Weekly interview notes, updated opportunity solution tree, growing insight repository, and pattern summaries for strategic reviews.","how":["Establish a weekly cadence – Block time every week for 1-2 customer interviews.","Automate recruitment – Set up an in-product prompt or use a panel service.","Connect to current decisions – Each week, identify the most important assumption or question from your current work.","Involve the product trio – PM, designer, and at least one engineer should attend together.","Synthesize incrementally – After each interview, update your opportunity solution tree or insight repository.","Track patterns over time – Over weeks and months, you'll see themes emerge that single-project research misses."],"wtu":["Your team makes product decisions without recent customer input","Research happens in big batches with long gaps between (feast-or-famine research)","You want to build deep, cumulative understanding of your users over time"],"wnu":["You're pre-launch with no users to interview","You're using continuous interviewing as a substitute for quantitative validation (interviews inform hypotheses; experiments validate them)","The team attends interviews but never changes behavior based on what they hear"],"kc":"","ai":"AI can transcribe interviews in real-time, suggest follow-up questions, identify patterns across weeks of interviews, and maintain the insight repository.","orig":"Teresa Torres, building on continuous discovery practices and opportunity solution trees.","eu":true,"lt":false,"lr":false,"pre":[]},{"id":"M65","n":"Experience Sampling Method (ESM)","desc":"Prompting participants at random or scheduled moments throughout their day to capture in-the-moment experiences, emotions, and behaviors. Unlike diary studies (typically participant-initiated), ESM uses researcher-triggered prompts to catch what people actually experience when it happens, reducing retrospective bias.","cat":"gen","tier":"spec","r":["V","U"],"s":["E"],"eff":"med","cx":"m","ts":["sm"],"cs":["any"],"t":"1-4 weeks","tn":"med","cost":"low","ev":"ms","evtype":"sr","out":"Temporal experience map showing in-the-moment ratings and qualitative reports across time, context, and activity. Statistical patterns of when and where experience peaks and valleys occur.","how":["Choose the sampling strategy – Signal-contingent, event-contingent (trigger after specific activity), or interval-contingent.","Design the micro-survey – 3-5 questions maximum per prompt.","Select an ESM tool – Dedicated ESM apps or repurpose messaging tools (SMS bots, chat platforms).","Recruit and onboard – 15-30 participants.","Run the sampling period – 1-2 weeks.","Analyze temporal patterns – Map experience quality across time of day, activity type, context, and emotional state."],"wtu":["You need to understand the lived experience of using your product (or the problem space) across real days and contexts","You suspect retrospective interviews are giving you a sanitized or biased account of user experience","Your product is used intermittently throughout the day and you need to capture real-time context"],"wnu":["You need a quick answer (ESM takes weeks, not days","The behavior you're studying is rare or infrequent (you'll get mostly irrelevant prompts)","Participant burden is a concern (ESM is demanding; executives, clinicians, and very busy users may not comply)","A diary study would answer your question (if participants can reliably self-trigger reports, diary studies are simpler)"],"kc":"","ai":"AI can analyze thousands of micro-survey responses, detect temporal patterns, cluster contextual factors, and identify anomalous experience moments for researcher deep-dives.","orig":"Mihaly Csikszentmihalyi and Reed Larson (1987). Originally developed to study the quality of everyday experience. Adapted for UX research and product discovery by HCI researchers at Carnegie Mellon, Microsoft Research, and others.","eu":false,"lt":false,"lr":false,"pre":[]},{"id":"M66","n":"Shadowing (Passive Observation)","desc":"Following users through their natural environment and workflow without interacting, interrupting, or asking questions. Pure observation – the researcher is a fly on the wall. Reveals unconscious behaviors, real workflows, and environmental factors that users edit out when they know they're being studied.","cat":"gen","tier":"ext","r":["V","U"],"s":["E"],"eff":"med","cx":"sm","ts":["solo","sm"],"cs":["scale","ent"],"t":"1-3 weeks","tn":"med","cost":"low","ev":"ms","evtype":"obs","out":"Observation logs, workflow diagrams, environment sketches, workaround inventory, and synthesized behavioral patterns with photos.","how":["Define the observation focus – What activity, workflow, or context are you studying? Set a clear scope but stay open to surprises.","Negotiate access and consent – Explain to participants that you'll observe silently.","Shadow silently – Follow the participant through their workflow for 2-4 hours.","Document everything – Photograph the environment (with permission).","Debrief AFTER – Only after the observation period, ask clarifying questions: \"I noticed you did X – can you tell me about that?\" Separating observation from questioning prevents participants from self-editing their behavior to match perceived expectations (demand characteristics) and avoids contaminating observation notes with post-hoc rationalizations.","Synthesize across sessions – Compare 3-8 shadowing sessions."],"wtu":["You suspect users behave differently than they say they do (say/do gap)","Active questioning (as in Contextual Inquiry) might change the behavior you're trying to observe","You need to understand the full environmental context – interruptions, social dynamics, physical setup","You're studying a workflow that is too routine for users to articulate (they can't tell you what they don't notice)"],"wnu":["You need to understand WHY users do things (shadowing shows what, not why","The environment is too private or sensitive for an observer","Remote users make physical shadowing impractical","The behavior is primarily digital with no physical component"],"kc":"","ai":"AI can help structure and analyze field notes, identify patterns across multiple shadowing sessions, and generate workflow diagrams from observation logs. Cannot replace being physically present.","orig":"Rooted in naturalistic observation traditions in ethology (animal behavior) and sociology. Applied to design by IDEO and service design practitioners. Distinguished from Contextual Inquiry (which adds active questioning) and Ethnographic Research (which involves cultural immersion and participation).","eu":false,"lt":false,"lr":false,"pre":[]},{"id":"M67","n":"Sales-Led Prototype Testing (The Demo Sell)","desc":"Presenting a working prototype to prospective customers within a real or realistic sales interaction, then measuring buying intent, objections, and deal progression. Uses the sales meeting as the test environment. Combines prototype validation with commercial signal in a single interaction.","cat":"exp","tier":"ext","r":["V","Vi"],"s":["Va"],"eff":"mh","cx":"m","ts":["sm"],"cs":["start","scale"],"t":"2-6 weeks","tn":"med","cost":"med","ev":"str","evtype":"beh","out":"Demo feedback log with buying signals, objections, feature requests, deal progression metrics, and go/no-go recommendation for production investment.","how":["Build a demo-ready prototype – Functional enough to demonstrate the core value proposition in a sales context.","Define the signals – What constitutes positive signal? Examples: \"Prospect asks about pricing\" (strong), \"Prospect asks about implementation timeline\" (strong), \"Prospect says 'interesting'\" (weak).","Set up real sales meetings – Use your existing pipeline or create targeted outreach.","Demo as if selling – Present the prototype as you would a real product.","Capture structured feedback – After the demo, ask: \"If this existed today, would you buy it? What's missing? What would you need to see to move forward? Who else would need to be involved?\".","Score and decide – Track signals across 5-15 meetings."],"wtu":["You're in B2B and want to validate both product-market fit AND commercial viability simultaneously","You have a working prototype and need to test it in a realistic buying context","Pre-sales conversations alone aren't enough – buyers need to see something working","You want to discover objections and deal-blockers before investing in production engineering"],"wnu":["You don't have a working prototype","Your sales team will oversell the prototype and set wrong expectations (prototype discipline required)","The product isn't in a category where demos are part of the buying process"],"kc":"","ai":"AI can analyze recorded demo sessions for engagement patterns, extract common objections, and score buying intent signals across meetings.","orig":"B2B product-led growth and enterprise sales practices. An applied validation tactic consistent with Steve Blank's customer development work – using a real sales interaction with a working prototype instead of a pitch to test buying intent before full production investment. Not a formally standardized method.","eu":false,"lt":false,"lr":false,"pre":["M29"]},{"id":"M68","n":"Dogfooding","desc":"Using your own product internally before releasing to external users. The team becomes the first user base, experiencing real friction, bugs, and usability issues firsthand. Turns every employee into a usability tester and every internal workflow into a test case.","cat":"exp","tier":"ext","r":["U","F"],"s":["Va","O"],"eff":"lm","cx":"s","ts":["xfn"],"cs":["any"],"t":"Ongoing","tn":"on","cost":"t0","ev":"mod","evtype":"obs","out":"Dogfooding feedback log with categorized issues, priority ranking, and release readiness assessment.","how":["Define the dogfooding scope – Which product features or workflows are you testing internally? The entire product or a specific new feature?.","Set up internal use – Deploy the product (or feature branch) for internal use.","Establish a feedback channel – Dedicated channel, bug report form, or weekly dogfooding standup.","Use it for real work – The key: internal use must be genuine, not performative.","Catalog findings – Track bugs, friction points, feature requests, and moments of delight.","Prioritize and fix – Use dogfooding findings as fast feedback before external release."],"wtu":["You're building a product your own team could plausibly use (tools, productivity, communication, developer tools)","You want fast, continuous feedback without formal research recruitment","You're about to launch a major release and need a \"canary\" group before general availability","Team empathy is low – engineers and PMs don't regularly experience the product as users do"],"wnu":["Your product is for a domain your team doesn't work in (medical software, construction tools, etc.) – your experience won't represent real users","Internal users are too forgiving or too technically savvy to represent the target audience","Dogfooding becomes a substitute for real user research (your team is NOT your customer)","The product is too early-stage to use for real work (forced dogfooding produces performative feedback)"],"kc":"","ai":"AI can aggregate and categorize dogfooding feedback from internal channels, identify duplicate reports, and prioritize by frequency and severity.","orig":"The term \"eating your own dog food\" originated at Microsoft in the 1980s (attributed to Paul Maritz). Practiced extensively by Microsoft, Google, Slack, Atlassian, Apple, and most successful product companies.","eu":false,"lt":false,"lr":false,"pre":[]},{"id":"M69","n":"Conjoint Analysis","desc":"A statistical technique that determines how users value different attributes of a product by presenting them with trade-off choices between bundles of features. Reveals the relative importance of each attribute and the optimal combination. A rigorous and widely used approach for pricing and feature-packaging decisions.","cat":"eval","tier":"spec","r":["Vi","V"],"s":["Va"],"eff":"mh","cx":"c","ts":["sm"],"cs":["scale","ent"],"t":"3-6 weeks","tn":"long","cost":"med","ev":"str","evtype":"sr","out":"Part-worth utility scores, attribute importance ranking, market simulation model, and optimal product configuration recommendations with willingness-to-pay estimates.","how":["Define attributes and levels – Choose 4-7 product attributes to test (e.g., price, features, support level, integration count).","Choose the conjoint type – Choice-Based Conjoint (CBC) is the most common: respondents choose between 2-3 product profiles per question.","Design the survey – Use conjoint software to generate choice tasks.","Field the survey – Target 200-500 respondents from your target market for reliable results.","Analyze with statistical software – Run Hierarchical Bayes (HB) estimation to determine part-worth utilities for each attribute level.","Build a market simulator – Use the utility scores to simulate market share for different product configurations and pricing scenarios."],"wtu":["You're making pricing decisions and need to understand willingness to pay for specific features","You need to optimize product packaging (which features in which tier)","You're comparing multiple feature combinations and need quantitative trade-off data","Stakeholders are debating pricing/packaging without user data"],"wnu":["You have fewer than 150 respondents – results won't be statistically reliable (150-200 is a commonly cited practical floor; the right number depends on the number of attributes, desired precision, and whether you need segment-level estimates)","Your product is too early-stage for users to evaluate feature trade-offs meaningfully","The attributes you're testing aren't independent (conjoint assumes attribute independence)","You need qualitative understanding of WHY users value certain attributes","You're testing too many attributes (> 7 creates respondent fatigue and unreliable data)"],"kc":"","ai":"AI can help design attribute/level combinations, analyze open-ended justifications from respondents, and run sensitivity analyses on the market simulator.","orig":"Mathematical psychology (Luce & Tukey, 1964). Adopted by marketing research in the 1970s-80s. Now standard in product management for pricing and packaging decisions.","eu":false,"lt":false,"lr":false,"pre":["M47"]},{"id":"M70","n":"First-Click Testing","desc":"Measuring where users click first when given a task on a page or interface. Tests whether the information architecture and visual hierarchy guide users to the right starting point. Research shows that users who get the first click right complete tasks successfully 87% of the time vs. 46% when the first click is wrong.","cat":"eval","tier":"ext","r":["U"],"s":["Va"],"eff":"low","cx":"s","ts":["solo"],"cs":["any"],"t":"1-3 days","tn":"fast","cost":"low","ev":"ms","evtype":"beh","out":"Click heatmap per task, first-click success rates, identification of misleading affordances, and design recommendations.","how":["Select the design to test – Static screenshot, wireframe, or prototype of the page/screen.","Write task scenarios – 3-5 realistic tasks: \"You want to change your password.","Set up the test – Upload the design to a first-click testing tool.","Recruit participants – 20-50 participants for reliable patterns.","Analyze click patterns – Generate click heatmaps.","Iterate the design – Fix areas with low first-click accuracy."],"wtu":["You're validating whether a page's navigation or layout guides users to the right place","You want a quick, quantitative signal on information architecture before full usability testing","You're comparing 2+ layout alternatives and need data on which performs better"],"wnu":["You need to test a multi-step flow (first-click only tests the starting point","The interface has no clear \"correct\" first action for the task","You're testing content comprehension rather than navigation"],"kc":"","ai":"AI can help generate task scenarios, analyze click distribution patterns, and identify design elements that create false affordances.","orig":"Bob Bailey and Cari Wolfson (2006) analyzed first clicks within broader usability studies and demonstrated strong predictive validity for task completion. The standalone first-click test format – presenting a design in isolation with a single task – was later developed and popularized by tools like Optimal Workshop and UsabilityHub (now Lyssna).","eu":false,"lt":false,"lr":false,"pre":[]},{"id":"M71","n":"Cognitive Walkthrough","desc":"A structured inspection method where evaluators step through a task from a new user's perspective, asking four specific questions at each step to identify learnability problems. Focuses specifically on whether first-time users can figure out how to accomplish goals without training.","cat":"eval","tier":"ext","r":["U"],"s":["Va"],"eff":"lm","cx":"m","ts":["solo","sm"],"cs":["any"],"t":"2-8 hours per task flow","tn":"fast","cost":"t0","ev":"mod","evtype":"ej","out":"Step-by-step walkthrough document with success/failure ratings per question, identified learnability barriers, severity rankings, and specific design recommendations.","how":["Define the user profile – Who is the target user? What is their goal? What experience/knowledge do they bring? Write this down explicitly – the walkthrough is from THIS user's perspective.","Define the task and correct action sequence – List every step the user must take to complete the task.","Walk through each step, asking four questions – At EACH action in the sequence, ask:\n   - Will the user try to achieve the right effect? (Do they know what to do next?)\n   - Will the user notice the correct action is available? (Is the control visible?)\n   - Will the user associate the correct action with the desired effect? (Is the label/icon clear?)\n   - If the user performs the correct action, will they see progress? (Is there feedback?)\n   Record a success/failure for each question at each step.","Document failure points – Where a question gets a \"no\" answer, document: the step, which question failed, why, and the likely user behavior (confusion, wrong path, abandonment).","Prioritize by severity – Failures at early steps are more critical (users may never reach later steps).","Recommend fixes – For each failure: what design change would turn the \"no\" into a \"yes\"? Be specific."],"wtu":["You want to evaluate learnability for new/first-time users without recruiting participants","You're designing onboarding flows, setup wizards, or first-run experiences","You need a learnability-focused inspection method – cognitive walkthrough examines a different dimension of usability than a general heuristic review (learnability vs. broad principles)","Budget or time prevents formal usability testing (cognitive walkthrough is faster and cheaper)"],"wnu":["You're evaluating expert/power user workflows (cognitive walkthrough is about learnability, not efficiency)","You want to understand real user behavior (this is expert inspection, not user testing","The interface is exploratory with no single correct path (the method requires a defined action sequence)"],"kc":"","ai":"AI can simulate the walkthrough by analyzing UI screenshots against the four questions, identify likely confusion points, and draft the walkthrough document for expert review and validation.","orig":"Developed by Cathleen Wharton, John Rieman, Clayton Lewis, and Peter Polson at the University of Colorado (1994). Based on CE+ theory of exploratory learning.","eu":false,"lt":false,"lr":false,"pre":[]},{"id":"M72","n":"Beta Testing / Controlled Pilot","desc":"Releasing a near-complete product or feature to a limited group of real external users under controlled conditions before general availability. Collects real-world usage data, bugs, and feedback at scale that internal testing and lab studies cannot replicate. Beta testing is typically a product-preview release; a controlled pilot is a more operationally focused field deployment – related but distinct formats.","cat":"exp","tier":"core","r":["V","U","F"],"s":["Va","O"],"eff":"high","cx":"c","ts":["xfn"],"cs":["scale","ent"],"t":"2-8 weeks","tn":"med","cost":"med","ev":"str","evtype":"beh","out":"Beta analysis report with usage metrics, bug severity distribution, satisfaction scores, feature feedback themes, and GA readiness recommendation.","how":["Define beta objectives – What specific questions must the beta answer? Feature completeness? Scalability? Usability in real environments? Market fit? Write measurable success criteria.","Select beta participants – Choose 20-500 users representing target segments.","Instrument for data collection – Set up analytics, error tracking, feedback mechanisms, and support channels BEFORE launch.","Launch and support – Release to beta group.","Monitor and iterate – Track usage metrics, bug reports, feature requests, and satisfaction scores throughout.","Analyze and decide – Did you hit success criteria? What's the quality/readiness signal? Categorize findings: must-fix-before-launch, should-fix-soon, nice-to-have."],"wtu":["You need real-world validation that lab testing and dogfooding can't provide (diverse environments, real data, real workflows)","You're launching a major release and need to de-risk before general availability","You want early adopters to become advocates and provide social proof at launch","The product involves integrations, infrastructure, or enterprise contexts that can only be tested in the field"],"wnu":["You're using beta as a crutch to avoid making the product ready (perpetual beta anti-pattern)","A smaller, faster experiment would answer your question","You can't properly support beta users (frustrated beta testers become detractors, not advocates)","The beta lacks clear success criteria (you'll get feedback but not answers)"],"kc":"","ai":"AI can triage and categorize beta feedback at scale, detect sentiment patterns, identify the most impactful bugs by user-impact analysis, and generate beta summary reports.","orig":"Software development practice dating to IBM's 1950s-60s terminology (alpha = internal testing, beta = external testing). Formalized as a product validation practice across all software categories.","eu":false,"lt":false,"lr":false,"pre":["M45"]},{"id":"M73","n":"Usability Benchmarking (Standardized Scoring)","desc":"Measuring perceived usability with a validated, standardized instrument – primarily SUS (System Usability Scale) or UMUX-Lite – to produce a comparable score that can be tracked over time, benchmarked against industry norms, and compared across product versions or competitors. Distinct from qualitative usability testing: the goal is a reliable score, not problem discovery.","cat":"eval","tier":"spec","r":["U"],"s":["Va","O"],"eff":"low","cx":"s","ts":["solo","sm"],"cs":["any"],"t":"1-3 days","tn":"fast","cost":"low","ev":"ms","evtype":"sr","out":"SUS or UMUX-Lite score(s) with trend over time, benchmark comparison, and grade interpretation. Optional: score by segment or by flow.","how":["Select instrument – SUS (10 items, widely benchmarked) or UMUX-Lite (2 items, faster).","Define the evaluation scope – Specify which product, feature, or flow participants will use before responding.","Recruit participants – 8-10 is a commonly cited practical floor for a reliable score; 20+ is often recommended for greater stability.","Administer the survey – Present immediately after a task or product interaction, before the experience fades.","Calculate scores – SUS scoring: odd items (1,3,5,7,9): score – 1; even items (2,4,6,8,10): 5 – score; sum all 10 values × 2.5 = score 0-100.","Interpret and benchmark – The Bangor et al.","Pair with qualitative follow-up – A score tells you where you are; interviews or usability testing tell you why."],"wtu":["Tracking usability improvement across release cycles with a consistent, comparable metric","Comparing the redesign against the current version on a common scale","Needing a single defensible usability metric for stakeholder reporting or competitive benchmarking","As a lightweight follow-up signal after moderated usability testing to track whether fixes worked"],"wnu":["You need to find specific usability problems (SUS scores don't tell you what to fix – use M16 or M17)","The product is too new for users to have formed a usability impression","Using a single rising score as the only usability signal without understanding the problems underneath it","Benchmarking against a non-comparable population (different user type, different task scope)"],"kc":"","ai":"Process SUS/UMUX-Lite responses at scale, calculate scores automatically, flag statistically significant changes across versions, and generate benchmark comparison reports. Cannot determine why a score changed – benchmarking measures score movement; qualitative testing (M16/M17) explains the cause.","orig":"SUS (System Usability Scale) created by John Brooke at Digital Equipment Corporation (1986), published in Usability Evaluation in Industry (1996). UMUX-Lite (Usability Metric for User Experience) developed by Kraig Finstad (2010) as a shorter, copyright-free alternative. Both are psychometrically validated instruments.","eu":false,"lt":false,"lr":false,"pre":[]},{"id":"M74","n":"In-Product Intercept Research","desc":"Triggering a brief research interaction – a micro-survey, short feedback prompt, or interview recruitment invitation – at a specific moment in the user's actual product experience. Captures contextual signal when the experience is fresh, without requiring separate recruitment or lab settings.","cat":"gen","tier":"ext","r":["V","U"],"s":["Va","O"],"eff":"lm","cx":"sm","ts":["solo","sm"],"cs":["any"],"t":"Days to 1-2 weeks","tn":"short","cost":"low","ev":"mod","evtype":"sr","out":"Quantitative summary of responses (satisfaction scores, yes/no rates), qualitative themes from open-text, recruited participants for follow-up interviews, and a decision update tied to the original research question.","how":["Define the research moment – Identify the specific in-product event that should trigger the intercept: task completion, feature first use, drop-off, session duration milestone.","Write the research question – One primary question with a clear decision tied to it.","Design the intercept – Micro-survey (2-4 questions max), sentiment emoji, open text, or recruitment invitation for a follow-up interview.","Configure targeting and frequency – Set the trigger event, sampling rate (not every user, every time), suppression rules, and exclusion criteria (support tickets open, trial expiring).","Run and monitor – Watch response rates daily.","Analyze and act – Cluster open-text responses, calculate satisfaction/clarity metrics, identify users who should be recruited for deeper interviews (M1)."],"wtu":["Immediately after a key interaction (onboarding, first feature use, checkout, support resolution) where contextual accuracy is highest","Recruiting follow-up interview participants from a relevant in-context moment","Measuring satisfaction or clarity at a specific touchpoint rather than overall","When email survey response rates are too low to be useful for specific-moment questions"],"wnu":["Interrupting users during complex or high-stakes tasks – this damages trust and produces frustrated responses","Overusing intercepts until users dismiss them habitually (response rate decline is the warning signal)","Asking questions answerable by behavioral analytics – don't ask \"did you complete the task?\" when your funnel data already answers it","Products without enough active users to generate meaningful signal in a reasonable time window"],"kc":"","ai":"Analyze large volumes of intercept responses, detect sentiment patterns across touchpoints, cluster qualitative feedback by feature or journey stage, and flag touchpoints with unusually low satisfaction for follow-up. Cannot replace the contextual interpretation of why a user felt frustrated or delighted at a specific moment – that requires interview follow-up (M1).","orig":"Grew from the expansion of in-product survey and NPS tooling in the 2010s – tools like Sprig (formerly UserLeap), Pendo, and Hotjar made event-triggered in-context prompts accessible to product teams. Referenced as a continuous discovery practice by Torres (Continuous Discovery Habits, 2021). Distinct from NPS (M12) and general surveys (M11) in its in-context, moment-specific triggering.","eu":true,"lt":true,"lr":false,"pre":[]},{"id":"M75","n":"Data-flow Mapping","desc":"Systematic mapping of what personal data a product collects, why it is collected, where it moves, who can access it, how long it is retained, and when it is deleted. Produces a data inventory and flow map – a practical and widely-used approach for meeting GDPR documentation obligations, and a standard input to DPIA, LIA, and Article 30 records of processing activities (RoPA).","cat":"com","tier":"ext","r":["C"],"s":["E"],"eff":"med","cx":"m","ts":["xfn"],"cs":["any"],"t":"Days to 1-2 weeks","tn":"short","cost":"t0","ev":"str","evtype":"ej","out":"Data inventory and flow diagram showing all personal data types, their sources, storage locations, access controls, purposes, and retention rules. Often feeds directly into Article 30 RoPA and DPIA inputs.","how":["Define scope – Which product, service, or feature are you mapping? Narrow to a specific data processing activity or system boundary.","Identify all data inputs – List every piece of personal data the system collects: what it is, from whom, through what mechanism (form, API, tracking, inference).","Trace data flows – For each data type, document: where it is stored, who can access it (internal roles, third-party processors, sub-processors), and what it is used for.","Document retention and deletion – For each data type: how long is it retained? Is there an automated deletion process? What triggers deletion?.","Identify legal basis – For each processing activity, note the GDPR lawful basis (or equivalent).","Review and validate – Walk through the map with engineering and legal to identify gaps, undocumented flows (shadow IT, analytics third parties), and discrepancies.","Document and maintain – Record the map in a format that can be updated as the system changes."],"wtu":["Before a DPIA or LIA – the data map is the required input","When building a new feature that touches personal data","When entering a new jurisdiction or onboarding a new third-party data processor","When the team cannot answer \"what data do we hold and where does it go?\""],"wnu":["As a one-time artifact that is never updated – an outdated data map creates false confidence","As a substitute for a DPIA when a DPIA is legally required","For products that collect no personal data"],"kc":"","ai":"AI can parse data schemas, API documentation, and code repositories to generate a draft data inventory for human verification. Cannot determine lawful basis, processing purposes, or retention obligations – those require human legal and product input.","orig":"Rooted in data governance and information security practice (data flow diagrams, DFDs, developed by DeMarco and Yourdon in the 1970s). Adopted as a privacy-specific practice to support compliance with GDPR (2018) and equivalent frameworks – GDPR does not mandate \"data-flow mapping\" by name, but requires organisations to document their processing activities (Article 30 RoPA) and conduct DPIAs where needed; data-flow mapping is a practical and widely-recognised method for meeting those obligations. The ICO explicitly identifies data-flow mapping as a practical starting point for documenting processing activities.","eu":false,"lt":false,"lr":true,"pre":[]},{"id":"M76","n":"Data Protection Impact Assessment (DPIA / PIA)","desc":"Structured assessment of whether planned personal data processing is likely to result in high risk to the rights and freedoms of individuals, what those risks are, and what mitigations are needed before launch. Under GDPR Article 35 a DPIA is legally mandatory before certain high-risk processing begins. A Privacy Impact Assessment (PIA) is a conceptually similar practice used outside the EU – less standardised across jurisdictions but widely adopted under US, Canadian, and Australian privacy frameworks.","cat":"com","tier":"ext","r":["C"],"s":["E"],"eff":"mh","cx":"mc","ts":["xfn"],"cs":["any"],"t":"1-2 weeks","tn":"short","cost":"med","ev":"str","evtype":"la","out":"DPIA report documenting processing description, necessity and proportionality assessment, identified risks, mitigations, residual risk, and DPO/supervisory authority consultation record where required.","how":["Screen for mandatory triggers – Check GDPR Article 35(3) and your supervisory authority's published mandatory list.","Describe the processing – Document what data is processed, for what purpose, by whom, how long it is retained, and who has access.","Assess necessity and proportionality – Is the processing limited to what is necessary for the stated purpose? Is the purpose legitimate? Could a less privacy-invasive approach achieve the same goal?.","Identify and assess risks – For each processing activity, identify risks to individuals' rights and freedoms: likelihood and severity.","Identify mitigations – For each identified risk, document the technical and organisational measures that reduce it.","Consult the DPO – Where a DPO exists, they must be consulted (Article 35(2)).","Document and review – Record the DPIA, link it to the product feature, and schedule a review date."],"wtu":["Before launching a feature meeting GDPR Article 35 mandatory triggers","As a structured risk-discovery exercise for any new product handling personal data at scale, even below the mandatory threshold","Before deploying a high-risk AI system that processes personal data (complement with M83 FRIA)","When entering a new EU market or processing EU resident data in new ways"],"wnu":["As a retrospective checkbox after launch – must be completed before processing begins","As a substitute for FRIA (M83) when the EU AI Act requires one – run both","When processing clearly falls below mandatory thresholds (a lighter data-flow map and screening may suffice)"],"kc":"","ai":"AI can populate a DPIA template from data-flow map and feature specification, and flag processing activities against mandatory-trigger criteria. Cannot assess necessity and proportionality, determine actual risk to individuals, or substitute for qualified legal review.","orig":"The PIA concept originated in US federal government practice (E-Government Act of 2002, OMB Circular A-130). The GDPR DPIA (2018) formalised and mandated a structured version for EU/UK contexts. The EDPB (formerly WP29) has published detailed guidelines on DPIAs. The ICO publishes the most widely used practitioner guidance in English.","eu":false,"lt":false,"lr":true,"pre":["M75"]},{"id":"M77","n":"Privacy Threat Modeling (LINDDUN)","desc":"Structured identification of privacy threats in a system's architecture, data flows, interfaces, and integrations before release. LINDDUN (KU Leuven; linddun.org) is the leading privacy-specific threat-modeling framework, covering seven canonical threat categories: Linking, Identifying, Non-repudiation, Detecting, Data Disclosure, Unawareness, and Non-compliance. Applies at design stage before code is committed. Distinct from STRIDE, which is a security threat model and does not address privacy-specific threats.","cat":"com","tier":"ext","r":["C"],"s":["E","Va"],"eff":"med","cx":"mc","ts":["xfn"],"cs":["scale","ent"],"t":"Days to 1-2 weeks","tn":"short","cost":"low","ev":"ms","evtype":"ej","out":"Privacy threat model: DFD with annotated threats, prioritised threat list, threat-mitigation mapping, and recommended design changes or PETs. Feeds into DPIA risk section.","how":["Create a Data Flow Diagram (DFD) – Map all system entities (external, internal), processes, data stores, and data flows.","Select the LINDDUN variant – Full LINDDUN for complex systems; LINDDUN GO (card-based) for lighter-weight workshops; LINDDUN Privacy Patterns for design-level guidance.","Apply the threat categories per DFD element – For each DFD element (data flow, process, data store, external entity), systematically ask whether each LINDDUN threat applies: Linking (can data be combined to infer more?), Identifying (can individuals be identified?), Non-repudiation (can actions be denied?), Detecting (can individual presence be inferred?), Data Disclosure (can data be accessed without authorisation?), Unawareness (are users unaware of processing?), Non-compliance (does processing violate regulations?).","Document threats – For each identified threat: describe the threat scenario, affected data types, affected individuals, and potential impact.","Prioritise threats – Rate by likelihood and impact.","Identify mitigations – Map each threat to applicable privacy-enhancing technologies (PETs) or design changes.","Feed into DPIA – Use the threat model output as structured input to the DPIA risk section (M76)."],"wtu":["After data-flow mapping, once architecture is sufficiently defined","Before a DPIA, to identify specific threat scenarios the assessment must address","For any product involving AI, automated decisions, or third-party data sharing where privacy risk is non-obvious","When your security team has run STRIDE and you need to complement it with privacy-specific analysis"],"wnu":["As a substitute for a DPIA – threat modeling identifies threats; the DPIA assesses risk and required mitigations","Before architecture is defined (no DFD = no meaningful threat analysis)","As a solo legal exercise – requires engineering understanding of system behavior"],"kc":"","ai":"AI can generate an initial list of LINDDUN threat scenarios from an architecture description or DFD for the team to validate and extend. Cannot assess which threats are realistic in context or replace engineering judgment about actual system behavior.","orig":"LINDDUN developed by Sabrina Capitanio, Koen Yskout, Dimitri Van Landuyt, Wouter Joosen, and Kim Wuyts at KU Leuven (Belgium), first published 2010. The framework has been refined through ongoing academic and practitioner work at KU Leuven's DistriNet research group. LINDDUN GO (a lightweight card-based variant) published 2020.","eu":false,"lt":false,"lr":true,"pre":["M75"]},{"id":"M78","n":"Participatory Engagement with Affected Communities","desc":"Structured research engagement with people who may be affected by the product – including non-users, communities, civil-society representatives, domain experts, and people with lived experience of relevant harms or exclusions. Used to surface rights impacts, discrimination risks, and unintended consequences that internal teams consistently miss. Recommended by NIST AI RMF as a structured way to gather input from affected communities and civil society when building AI systems. Distinct from standard user interviews (M1): the purpose is harm and rights discovery, not value or usability validation.","cat":"com","tier":"spec","r":["C"],"s":["E","Va"],"eff":"high","cx":"c","ts":["xfn"],"cs":["any"],"t":"2-4 weeks minimum","tn":"med","cost":"med","ev":"ms","evtype":"sr","out":"Harm and risk findings report: identified harm types, affected groups, representative quotes, risk prioritisation, and recommended product changes. Often includes a documented response to each finding.","how":["Identify affected communities – Who beyond the direct user could be affected? Consider: marginalised groups, non-users who interact with the system indirectly, communities in specific geographic or regulatory contexts, people with disabilities, children.","Design for genuine participation – Define the engagement format: interviews, focus groups, co-design workshops, surveys, community advisory boards.","Recruit with care – Do not recruit through your existing product user channels alone.","Run the engagement – Focus on: what harms could this product cause? What exclusions? What rights does it affect? What would make you trust or distrust it? What would you want changed? Use structured prompts but allow open exploration.","Synthesise harm and risk findings – Cluster findings by harm type and affected group.","Feed findings into product decisions – Map each identified harm or risk to a product design question.","Close the loop – Share findings and product responses back with participating communities where possible."],"wtu":["Building products with consequential decisions affecting people – employment tools, credit, healthcare, education, public services, or AI systems","When DPIA or FRIA (M83) identifies impact on vulnerable or marginalised groups","Before designing consent or transparency mechanisms for populations with low digital literacy","When your team lacks lived experience of the affected context"],"wnu":["As PR rather than genuine input into product decisions","When participation is not compensated (extractive research damages community trust and produces poor data)","For low-risk features with no meaningful impact on rights or wellbeing","As a substitute for other compliance assessments – this generates qualitative insight, not legal sign-off"],"kc":"","ai":"AI can synthesise themes across session notes, support multilingual note translation, and structure harm scenarios from raw findings. Cannot replace genuine engagement – AI-simulated community voices are not a substitute for real affected people and produce systematically biased outputs.","orig":"Rooted in participatory design research (Scandinavian tradition, 1970s-80s; Bjerknes & Bratteteig, Nygaard). Extended into AI ethics and human rights practice by organisations including the Partnership on AI, AI Now Institute, Algorithmic Justice League, and NIST. The NIST AI Risk Management Framework (AI RMF, 2023) explicitly includes participatory engagement as a structured socio-technical practice for AI risk identification.","eu":false,"lt":false,"lr":true,"pre":[]},{"id":"M79","n":"Transparency and Notice Comprehension Testing","desc":"User testing of privacy notices, consent language, cookie banners, and AI interaction disclosures – to determine whether people can find, read, understand, and act on them. Tests comprehension and usability, not legal presence alone. The ICO explicitly recommends user-testing privacy information before launch to check whether people can access and understand it.","cat":"com","tier":"ext","r":["C"],"s":["Va"],"eff":"lm","cx":"sm","ts":["solo","sm"],"cs":["any"],"t":"Days to 1-2 weeks","tn":"short","cost":"low","ev":"mod","evtype":"obs","out":"Comprehension test report with per-question pass/fail rates, identified failure points, participant quotes, and revised notice text. Provides evidence of genuine transparency effort.","how":["Identify what to test – Privacy notice? Cookie banner? Consent flow? AI interaction disclosure? Data subject rights information? Select the specific notice or flow to test.","Define comprehension questions – What do you need users to understand? Examples: What data is collected? What are their rights? What does this AI feature do with their data? How do they opt out? Draft 5-8 specific comprehension questions.","Recruit representative participants – Target your actual user population.","Run think-aloud sessions – Show participants the notice or consent flow.","Measure comprehension – Score each participant on each comprehension question.","Revise and re-test – Rewrite sections that fail comprehension checks.","Document results – Record comprehension scores, specific failure points, and changes made."],"wtu":["Before launching a new privacy notice, consent flow, or cookie banner","When redesigning disclosures after a regulatory change (GDPR, AI Act, CCPA)","Before deploying an AI feature with a required user-facing disclosure","When legal has written the notice and no one has verified that real users can understand it"],"wnu":["As legal sign-off – comprehension testing confirms understanding, not legal compliance","As a substitute for DPIA","When the product has no user-facing privacy or transparency mechanisms to test"],"kc":"","ai":"AI can analyse notice text for reading complexity (Flesch-Kincaid, SMOG), flag legal jargon likely to cause comprehension failure, and generate plain-language rewrite drafts for legal review. Cannot replace testing with real users – automated scores do not predict whether users understand specific consent trade-offs or their rights.","orig":"Rooted in plain-language research (Redish, J.C., 1985 onwards) and usability testing methodology. Applied specifically to privacy notices as a compliance practice from the early GDPR implementation period (2018-2020). The ICO, EDPB, and FTC have all published guidance emphasising that legal presence of a notice does not satisfy transparency obligations if users cannot understand it.","eu":false,"lt":false,"lr":true,"pre":["M76"]},{"id":"M80","n":"Fairness and Bias Assessment","desc":"Evaluation of whether a system performs differently across demographic groups or creates unequal harm – including disaggregated performance analysis and subgroup testing for disparate impact. The primary validation method for discrimination and equity risk in AI and algorithmic products. EU AI Act obligations for high-risk AI systems (Articles 9 and 10) require training and testing data to be sufficiently representative, bias to be minimised, and bias detection and correction to be supported. Mandated as an independent third-party audit in specific jurisdictions for specific use cases (e.g. NYC Local Law 144 for AI-assisted employment decisions in New York City).","cat":"com","tier":"ext","r":["C"],"s":["Va","O"],"eff":"mh","cx":"mc","ts":["xfn"],"cs":["scale","ent"],"t":"1-2 weeks","tn":"short","cost":"med","ev":"str","evtype":"ej","out":"Bias assessment report with disaggregated performance metrics by demographic group, identified disparities, root cause analysis, applied mitigations, residual disparity documentation, and deployment decision rationale.","how":["Define the fairness question – What decisions or outputs might disadvantage certain groups? Which demographic attributes are relevant (race, gender, age, disability, postcode as a proxy)? What outcome disparity would constitute harm? Define this before running analysis to avoid post-hoc rationalisation.","Collect disaggregated data – Obtain ground-truth labels, system outputs, and demographic data for a representative evaluation dataset.","Measure overall performance – Establish baseline performance metrics (accuracy, precision, recall, F1) on the full evaluation set.","Disaggregate by subgroup – Run the same analysis for each demographic group and subgroup.","Identify and assess disparities – Where do group-level metrics diverge significantly? Assess severity: magnitude of disparity, number of affected individuals, nature of harm (false positives vs.","Investigate root causes – Is disparity caused by training data imbalance? Label bias? Proxy features? Feature engineering choices? Understanding the cause determines the correct mitigation.","Apply and re-evaluate mitigations – Apply pre-processing (data rebalancing), in-processing (fairness constraints), or post-processing (threshold adjustment) mitigations as appropriate.","Document and disclose – For regulated contexts, produce a structured bias audit report."],"wtu":["Before deploying any AI or algorithmic system making consequential decisions about people","When DPIA or FRIA identifies discrimination as a risk","After significant model updates or retraining","As a recurring Optimize-stage practice for live systems"],"wnu":["As a substitute for participatory engagement (M78) – bias testing reveals statistical disparities; it does not reveal what harms they cause to affected communities","When you lack sufficient disaggregated data (address the data collection gap first)","When the system does not make or influence decisions about people"],"kc":"","ai":"AI can generate disaggregated performance breakdowns from evaluation datasets, flag subgroups with statistically significant performance gaps, and produce structured audit reports for human interpretation. Cannot determine which disparities constitute legally or ethically unacceptable harm – that requires human and legal judgment. Cannot compensate for missing demographic data.","orig":"Rooted in anti-discrimination law and statistical disparate impact analysis (US Civil Rights Act, 1964; Griggs v. Duke Power, 1971). Operationalised as a technical product method through fairness-aware machine learning research (Dwork et al., 2012; Hardt, Price & Srebo, 2016). Mandated as a product practice by NYC Local Law 144 (2021) and EU AI Act (2024).","eu":false,"lt":false,"lr":true,"pre":["M75","M76"]},{"id":"M81","n":"AI Red Teaming / Adversarial Testing","desc":"Deliberate, structured probing of an AI system by a team of testers using adversarial prompts, edge-case scenarios, and realistic misuse attempts – to expose harmful, unsafe, discriminatory, policy-breaking, or non-compliant outputs before deployment. Distinct from automated evaluation: red teaming is hypothesis-driven and conducted by humans reasoning about harm in context. Recommended by NIST AI RMF. Mandatory under EU AI Act Article 55(1)(a) specifically for providers of general-purpose AI models (GPAI) with systemic risk – not a general requirement for all high-risk AI providers, who have separate obligations under Articles 9 and 15.","cat":"com","tier":"ext","r":["C"],"s":["Va","O"],"eff":"mh","cx":"c","ts":["xfn"],"cs":["scale","ent"],"t":"1-2 weeks","tn":"short","cost":"med","ev":"ms","evtype":"ej","out":"Red team report: harm taxonomy with coverage, findings per harm category, severity ratings, representative examples, mitigations applied, and residual risk documentation. For regulated GPAI models, this feeds into Article 55 documentation obligations.","how":["Define scope and harm taxonomy – What system are you testing (base model, RAG pipeline, fine-tuned model, application layer)? What harm categories are in scope: harmful content generation, jailbreaks, discriminatory outputs, privacy violations, manipulation, misuse for illegal purposes? Build a harm taxonomy before testing begins.","Assemble a diverse red team – Include people with different backgrounds, domain expertise, and lived experience of the harms you are testing for.","Open-ended exploration – Testers freely probe the system using their judgment, trying to elicit harmful outputs.","Develop targeted test cases – From the open-ended findings, create a structured set of adversarial test cases for each harm category.","Systematic guided testing – Run the targeted test cases systematically.","Document findings – For each harm: describe the attack vector, representative examples, severity, frequency, and recommended mitigation.","Feed into product changes – Map findings to mitigations: prompt engineering, fine-tuning, output filtering, UX safeguards, human review triggers."],"wtu":["Before deploying any AI system that generates content, takes actions, or influences decisions in ways that could cause harm","After significant model updates, prompt changes, or system integrations","When DPIA or FRIA (M83) identifies safety or misuse risk","As a recurring Optimize-stage practice for live AI products"],"wnu":["As a substitute for automated evaluation – red teaming generates the harm hypothesis list; automated evaluation measures it at scale","As a one-time pre-launch exercise treated as permanent sign-off","With a homogeneous internal team for systems affecting diverse populations"],"kc":"","ai":"AI can generate adversarial prompt variants from a seed scenario, cluster findings by harm category, and draft the harm taxonomy before the session. Cannot conduct red teaming itself – AI-generated adversarial prompts miss the contextually-grounded, socially-aware harm scenarios that human testers with lived experience identify.","orig":"Adapted from military adversarial exercises and security penetration testing (1960s-70s). Applied to AI safety by major AI labs from 2020 onward (Microsoft, Google DeepMind, OpenAI, Anthropic). Formalised in NIST AI RMF (2023). Mandated for GPAI systemic risk providers by EU AI Act Article 55(1)(a) (2024).","eu":false,"lt":false,"lr":true,"pre":["M77"]},{"id":"M82","n":"Post-market Compliance Monitoring and Incident Review","desc":"Ongoing monitoring of a live product for harmful outcomes, rights failures, bias drift, serious incidents, and user complaints signalling compliance failures – with structured review and corrective action when issues are found. Distinct from standard product analytics (M55–M59), which track behavioral and business metrics: this method tracks rights, safety, and compliance signals. EU AI Act Article 72 requires high-risk AI providers to have a post-market monitoring plan; incident reporting and serious incident review obligations apply alongside.","cat":"com","tier":"ext","r":["C"],"s":["O"],"eff":"med","cx":"m","ts":["xfn"],"cs":["any"],"t":"Ongoing","tn":"on","cost":"low","ev":"str","evtype":"ej","out":"Post-market monitoring report (monthly/quarterly): compliance signal summary, incidents reviewed, root cause analyses, corrective actions taken, residual risk updates, and regulatory reporting log.","how":["Define compliance signals to monitor – What would indicate a compliance failure? Examples: user complaints mentioning privacy, discrimination, or harm; support tickets in specific categories; bias drift in model outputs; legal notices or regulatory enquiries; serious incident reports.","Set up monitoring infrastructure – Route complaints and support tickets through a compliance-category classification system.","Establish a review cadence – Monthly or quarterly structured review of all compliance signals.","Run structured incident reviews – For each flagged incident: describe what happened, assess impact on individuals' rights or safety, identify root cause, determine whether it constitutes a legally reportable serious incident (EU AI Act Article 73 criteria), and document the corrective action taken.","Track residual risks from pre-launch assessments – Review whether risks identified in pre-launch DPIAs, FRIAs, or bias assessments have materialised.","Report to the DPO and legal team – Provide structured summary of compliance monitoring findings at each review.","Close the loop on corrective actions – Document what changed in the product as a result of monitoring findings."],"wtu":["As best practice after launching any product handling personal data at scale or making algorithmic decisions – regardless of whether a formal legal obligation applies","When EU AI Act Article 72 post-market monitoring obligations apply (mandatory for high-risk AI system providers)","When DPIA or FRIA identified residual risks to track after launch","After any significant model, data, or deployment context change"],"wnu":["As a substitute for pre-launch compliance work – monitoring finds problems that escaped pre-launch assessment, not structural risks that should have been addressed earlier","When monitoring outputs are not connected to a corrective-action process (monitoring without action is theater)"],"kc":"","ai":"AI can classify complaints and tickets by compliance signal type, detect anomalies in subgroup performance indicating bias drift, and generate structured incident summaries for human review. Cannot determine whether a pattern constitutes a legally reportable serious incident, cannot substitute for legal judgment, and cannot make corrective-action decisions.","orig":"Rooted in post-market surveillance practices from regulated industries (FDA medical device post-market surveillance, pharmaceutical pharmacovigilance). Applied to AI and software products through EU AI Act Article 72 (2024) and NIST AI RMF GOVERN and MANAGE functions (2023). Incident review practices established in information security (NIST SP 800-61) applied to compliance context.","eu":true,"lt":true,"lr":true,"pre":[]},{"id":"M83","n":"Fundamental Rights Impact Assessment (FRIA)","desc":"Assessment of how a high-risk AI system may affect fundamental rights – including non-discrimination, privacy, dignity, due process, and freedom of expression – in its real deployment context. Under EU AI Act Article 27, certain deployers must complete a FRIA prior to first use. Complements the DPIA (M76), which addresses privacy risk specifically: the FRIA addresses the broader fundamental rights picture. Conceptually related to Human Rights Impact Assessment (HRIA) practice used in the broader digital-rights and corporate due-diligence context.","cat":"com","tier":"spec","r":["C"],"s":["E","Va"],"eff":"mh","cx":"mc","ts":["xfn"],"cs":["any"],"t":"1-2 weeks","tn":"short","cost":"med","ev":"str","evtype":"la","out":"FRIA report documenting: system and deployment context description, affected people and groups, rights impact assessment per right, identified mitigations, residual impacts, consultation record, and review schedule.","how":["Determine scope and obligation – Does EU AI Act Article 27 apply? Qualifying deployers: (a) public-law bodies and private entities providing public services deploying most Annex III high-risk AI systems; (b) all deployers of Annex III point 5(b) systems (creditworthiness/credit scoring) and 5(c) systems (life and health insurance risk).","Describe the system and its deployment context – What does the system do? Where is it deployed? Who operates it? Who is affected? What decisions does it influence? Be specific about the real use context, not the intended use in isolation.","Identify affected people and groups – Who interacts with the system directly? Who is affected by its outputs indirectly? Which groups may be disproportionately affected? Consider: people subject to automated decisions, marginalised groups, people with disabilities, children, groups with limited means to challenge decisions.","Assess fundamental rights impacts – For each relevant right, assess: is the right affected? How? With what likelihood and severity? Consider both direct impacts (the system makes a decision) and indirect impacts (the system changes how a human makes a decision).","Identify mitigations – For each identified impact: what changes to system design, deployment practice, human oversight, or redress mechanisms would reduce the impact? Document which mitigations are feasible and which residual impacts remain.","Consult affected communities – For significant impacts, incorporate input from affected individuals or their representatives (link to M78).","Document and make available – Record the FRIA, store it, and make it available to competent authorities on request."],"wtu":["Before deploying any high-risk AI system in the EU (mandatory for qualifying deployers under Article 27)","To complement a DPIA when the system involves broader rights risks beyond privacy","When stakeholders require evidence that fundamental rights have been considered before deployment"],"wnu":["As a substitute for a DPIA when GDPR Article 35 applies – FRIA and DPIA are complementary, not interchangeable; run both when both apply","Before the deployment context and intended use are sufficiently defined","As a legal-team-only exercise – the assessment requires knowledge of how the system actually works in practice"],"kc":"","ai":"AI can draft a structured FRIA template from system documentation and deployment context description, and generate a list of affected rights and affected groups to review and extend. Cannot assess actual rights impact – that requires human judgment, legal expertise, and ideally input from affected communities (M78).","orig":"Derived from human rights impact assessment practice (UN Guiding Principles on Business and Human Rights, 2011; Ruggie Framework). Applied to AI specifically through the EU AI Act (2024) as a mandatory pre-deployment requirement for qualifying deployers. Article 27(5) requires the AI Office to develop a standard questionnaire template for conducting FRIAs.","eu":false,"lt":false,"lr":true,"pre":["M75","M76"]},{"id":"M84","n":"Legitimate Interests Assessment (LIA)","desc":"Structured three-part assessment used when an organisation intends to rely on GDPR Article 6(1)(f) – legitimate interests – as the lawful basis for personal data processing. Tests: (1) Purpose test – is the processing for a genuine, legitimate purpose? (2) Necessity test – is the processing limited to what is necessary? (3) Balancing test – do the controller's interests override the rights and interests of data subjects? If the balancing test fails, legitimate interests cannot be used and another lawful basis must be found or the processing must not proceed. A documented LIA is the standard and strongly recommended way to demonstrate that the Article 6(1)(f) conditions are met – not itself a named statutory instrument, but the recognised operational mechanism. Product teams are increasingly expected to participate in the three-part test, not only receive the outcome.","cat":"com","tier":"spec","r":["C"],"s":["E"],"eff":"lm","cx":"sm","ts":["solo","sm"],"cs":["any"],"t":"Hours to days","tn":"fast","cost":"t0","ev":"mod","evtype":"la","out":"LIA documentation: processing description, purpose test outcome, necessity test outcome, balancing test outcome with reasoning, and overall conclusion on whether legitimate interests can be relied upon.","how":["Identify the processing activity and intended basis – What data are you processing? For what purpose? Why are you considering legitimate interests rather than consent, contract, or legal obligation? Document the reason you believe this basis is appropriate before running the test.","Purpose test – Is the purpose genuine and legitimate? Legal purposes are legitimate.","Necessity test – Is the processing limited to what is necessary to achieve the stated purpose? Could the purpose be achieved with less data, less intrusive processing, or a less privacy-invasive approach? The test fails if any less-intrusive alternative would achieve the same goal.","Balancing test – Do the controller's interests override the data subjects' rights and interests? Consider: the nature of the data (more sensitive = higher weight to data subject interests), reasonable expectations (would data subjects expect this processing?), potential harm, the power imbalance between controller and data subject.","Document the outcome – Record the assessment with the reasoning for each part of the test.","Review when circumstances change – The LIA is not permanent."],"wtu":["Before relying on legitimate interests as the GDPR lawful basis for any processing activity","When a data-flow map (M75) has identified processing activities without a clear lawful basis","When deciding whether to use consent or legitimate interests for a feature – an LIA makes the decision defensible"],"wnu":["As a mechanism to avoid obtaining consent when consent is the appropriate basis – legitimate interests cannot be used for processing requiring explicit consent (special category data, most direct marketing, processing without a compelling legitimate purpose)","When the conclusion is predetermined – the balancing test must be genuinely conducted; a pro-forma LIA that always passes does not meet GDPR requirements"],"kc":"","ai":"AI can draft the three-part assessment structure from a processing description and identify analogous EDPB and ICO guidance for the use case. Cannot determine whether the balancing test is met – that requires qualified privacy counsel.","orig":"Derived directly from GDPR Article 6(1)(f) and its predecessor in EU Directive 95/46/EC. The three-part test structure was formalised in EDPB (WP29) guidance and is the ICO's recommended approach. The \"legitimate interests\" basis has existed in EU data protection law since 1995 but became practically important to product teams following GDPR enforcement (2018 onward).","eu":false,"lt":false,"lr":true,"pre":["M75","M76"]},{"id":"M90","n":"AI Capability Assessment","desc":"A structured probe to determine whether available AI technology – a foundation model, API, fine-tuned model, or internal ML system – can meet the performance threshold required for a specific feature to be viable. Run against a curated sample of real representative tasks before committing to development. Answers the question \"can the AI actually do this well enough?\" with evidence, not assumption.","cat":"exp","tier":"ext","r":["F"],"s":["E","Va"],"eff":"lm","cx":"sm","ts":["solo","sm"],"cs":["any"],"t":"1-5 days","tn":"fast","cost":"low","ev":"mod","evtype":"beh","out":"Capability assessment report with test set specification, results against acceptance criteria, confidence rating (Confirmed/Conditional/Gap), and a go/no-go recommendation with explicit rationale. If conditional: list of constraints under which the capability is viable.","how":["Define the capability claim precisely – \"The model can classify X into Y categories with >Z% precision on our specific data\".","Set acceptance criteria – define the viability threshold before running the test.","Assemble a representative test set – 30-100 real cases including typical cases, edge cases, and known failure modes; draw from real user data where possible.","Run the test – through the AI system, model, or API under realistic conditions.","Score outputs – against acceptance criteria: precision, recall, hallucination rate, latency, output quality.","Document results – as: capability confirmed / capability gap / capability conditional (viable with constraints).","Make the go/no-go decision – with explicit evidence."],"wtu":["Before committing engineering resources to an AI feature","When evaluating a new model or API for a specific use case","When the team is debating \"can current AI do this?\" without evidence","When comparing multiple model options for the same task","After a model update to detect capability regression"],"wnu":["When the capability is well-established and pre-benchmarked for your exact use case","For non-AI features","As a substitute for production testing – this is discovery-level signal, not production QA","When the test set cannot be drawn from real representative data (synthetic test sets produce false confidence)"],"kc":"","ai":"AI can help generate diverse test cases from a seed set, identify edge cases the team hasn't considered, and score outputs against a rubric at scale – significantly reducing the manual evaluation burden. Cannot replace human judgment on what \"good enough\" means for your specific context.","orig":"Emergent practice in AI product development; no single canonical source. Grounded in ML model evaluation traditions (benchmark testing, held-out test sets) adapted for product discovery decision-making. NIST AI Risk Management Framework (2023) includes structured capability evaluation (TEVV – Test, Evaluate, Verify, and Validate) as a core practice. Note: EU AI Act (2024) conformity assessment for high-risk systems is a separate regulatory obligation with its own requirements – it is not the same as this discovery-stage capability probe, and the Act does not formalise this specific product discovery practice. The product discovery framing – running capability tests before committing to build – is a practitioner synthesis.","eu":false,"lt":false,"lr":false,"pre":["M89"]},{"id":"M91","n":"Data Readiness Assessment","desc":"A structured discovery activity to evaluate whether the data required for an AI feature – training data, fine-tuning data, retrieval/RAG data, or evaluation data – is available, representative, permissioned, and quality-sufficient before committing to development. Surfaces the most common silent killer of AI features: the data doesn't exist, isn't accessible, or isn't good enough.","cat":"gen","tier":"ext","r":["F","C"],"s":["E"],"eff":"lm","cx":"sm","ts":["sm"],"cs":["any"],"t":"1-3 days","tn":"fast","cost":"t0","ev":"mod","evtype":"ej","out":"Data readiness map showing each required data source rated Green/Amber/Red across availability, permissions, quality, and volume. Includes a gap register with remediation effort estimates and a recommendation: proceed / proceed with constraints / pivot approach / abandon.","how":["List data requirements – training data, fine-tuning examples, retrieval corpus, evaluation set.","Assess each data source – across four dimensions:\n   - Availability: Does the data exist? Where is it stored? Can the team access it?\n   - Permissions: Is it permissioned for this AI use case? Who owns it? Are there consent or data processing boundaries?\n   - Quality: Is it clean, labelled, representative of the target use case, and free of critical biases?\n   - Volume: Is there enough data to achieve the required model performance or retrieval coverage?.","Rate each source – Green (ready), Amber (gaps but fixable), Red (blocker).","Estimate remediation – for each Red or Amber: effort and timeline.","Identify feature-level impact – does any data gap kill the feature concept or change the required approach?.","Document findings – as a data readiness map; feed blockers into M89 Capability Contract (Retrieval Scope gaps) and M76 DPIA (permission gaps)."],"wtu":["Before committing to any AI feature requiring proprietary or curated data","When evaluating different AI architectures with different data dependencies","When proposing to fine-tune or train a model on internal data","When compliance requires documenting data provenance and consent","When the team assumes \"we have the data\" without having verified it"],"wnu":["For AI features using only public foundation models via API with no custom data layer","When data availability is already formally documented and verified","As a substitute for a full data governance audit – this is discovery-level signal, not compliance certification"],"kc":"","ai":"AI can help generate the assessment framework for a specific feature type, suggest common data quality dimensions for the domain, and draft the gap analysis document from interview notes. Cannot assess actual data quality or permissions – that requires human access to the data systems.","orig":"Adapted from data management and ML engineering practice for product discovery. Foundational concept: Lawrence, N.D. (2017). \"Data Readiness Levels.\" arXiv:1705.02245 – proposed a structured maturity model for data availability and usability. Data quality assessment grounded in DAMA International (2017). The product discovery framing – using data readiness as an early-stage feasibility gate before committing to build – is a practitioner synthesis for AI product teams.","eu":false,"lt":false,"lr":"conditional","pre":["M89"]},{"id":"M92","n":"Churn and Lost Customer Interviews","desc":"Direct qualitative interviews with customers who recently churned, downgraded, cancelled, or chose not to renew – to discover the real reasons for leaving. Distinct from user interviews (M1) by population (non-users who left, not current users) and goal (understanding exit decisions and the forces that drove them, not unmet needs for active users). Related to JTBD Switch Interviews (M2) through the \"fire\" event – but focused on churn cohorts rather than switchers who adopted a new solution.","cat":"gen","tier":"core","r":["V","Vi"],"s":["E","Va"],"eff":"med","cx":"m","ts":["solo","sm"],"cs":["scale","ent"],"t":"1-2 weeks","tn":"short","cost":"low","ev":"str","evtype":"sr","out":"Churn interview synthesis: exit reason taxonomy, frequency by theme, representative quotes, and recommended product or process changes. Optional: Four Forces diagram populated with exit data.","how":["Define the churn cohort – Identify who counts as churned for this study: cancelled in the last 30-90 days, downgraded, did not renew.","Segment by churn type – Distinguish voluntary churn (active cancellation), involuntary churn (payment failure), and downgrade.","Prepare outreach – Write a brief, honest outreach message.","Run 30-45 minute semi-structured interviews – Open with: \"Walk me through the moment you decided to cancel.\" Do not defend the product.","Map against the Four Forces – Apply the JTBD Forces framework (M88): what Push forces made staying untenable? What was the final trigger? Were there Anxiety forces about the product that were never resolved? (During synthesis).","Identify exit themes – Cluster reasons across interviews: product gap, price, competitive alternative, lifecycle change, support failure, onboarding failure.","Feed into retention and roadmap decisions – Map themes to product decisions: what would have kept them? What is fixable? What is outside scope?."],"wtu":["When churn rate is above acceptable threshold and you don't know the real reasons","When survey data gives \"too expensive\" or \"missing features\" but no actionable signal","When preparing a retention initiative and need to distinguish real exit reasons from stated ones","When NPS or CES scores drop and you need to understand what changed"],"wnu":["As a substitute for proactive retention work – exit interviews are a lagging indicator; use M60 (Continuous Interviewing) to catch signals before churn occurs","When you have fewer than 10-15 churned customers to contact (too thin for meaningful patterns)","When the real purpose is win-back, not learning – churned customers can tell when they are being sold to, and it invalidates the data","Within 48 hours of cancellation when emotional valence is too high for structured reflection"],"kc":"","ai":"AI can cluster interview transcripts by exit theme, identify language patterns signalling product gap vs. competitive loss vs. lifecycle exit, and generate a structured synthesis document. Cannot distinguish genuine product feedback from rationalisation – human interpretation of emotional cues in transcripts remains important.","orig":"Derived from customer success and retention practice in SaaS and subscription businesses, formalised in product and growth management writing from 2010 onward. The \"fire\" half of the JTBD Switch Interview (Moesta, 2020) provides the strongest theoretical foundation. Churn analysis as a structured discovery practice distinct from exit surveys is an operational synthesis.","eu":true,"lt":false,"lr":false,"pre":[]},{"id":"M93","n":"Pricing and Willingness-to-Pay Testing","desc":"Survey-based methods to determine acceptable price ranges and purchase-intent thresholds before pricing decisions are committed. Covers two primary instruments: Van Westendorp Price Sensitivity Meter (four questions establishing cheap/expensive/too-cheap/too-expensive thresholds that define an acceptable price range) and Gabor-Granger (iterative purchase-intent questions at fixed price points, producing a demand curve). Lighter-weight and faster than Conjoint Analysis (M69) but limited to price in isolation rather than price as a trade-off against features. Distinct from M69 in that it asks about price alone, not about feature bundles at varying prices.","cat":"eval","tier":"ext","r":["Vi","V"],"s":["Va"],"eff":"lm","cx":"sm","ts":["solo","sm"],"cs":["any"],"t":"1-2 weeks","tn":"short","cost":"low","ev":"mod","evtype":"sr","out":"Acceptable Price Range and Optimal Price Point from Van Westendorp, or demand curve and revenue-maximising price from Gabor-Granger. Includes interpretation document with recommended pricing range and key caveats.","how":[],"wtu":["Before committing to a pricing model for a new product or significant feature","When internal pricing debate lacks external signal and is stalling decisions","As a faster and cheaper alternative to Conjoint when price-only data is sufficient","After a pricing change that produced unexpected churn – to understand where the threshold was crossed"],"wnu":["When price is inseparable from feature trade-offs – use Conjoint (M69) instead","When the product has no comparable, making price questions too abstract for reliable responses","As the sole input to a pricing decision – stated willingness-to-pay consistently overstates revealed willingness-to-pay; validate with behavioral signals (M23, M48)","For freemium conversion pricing where social and habit factors dominate rational pricing logic"],"kc":"","ai":"AI can design Van Westendorp or Gabor-Granger survey instruments, analyse intersection curves from response data, and generate pricing range summaries. Cannot correct for the stated-vs-revealed willingness-to-pay gap – behavioral validation is required.","orig":"Van Westendorp, P. (1976). \"NSS-Price Sensitivity Meter (PSM) – a New Approach to Study Consumer Perception of Price.\" Proceedings of the ESOMAR Congress. Gabor, A. & Granger, C.W.J. (1966). \"Price as an Indicator of Quality: Report on an Enquiry.\" Economica 33(129), 43-70. Both instruments developed independently in pricing research and adopted as practical product and market research tools from the 1980s onward.","eu":false,"lt":false,"lr":false,"pre":["M47","M48"]},{"id":"M94","n":"Search and Query Log Analysis","desc":"Systematic analysis of what users search for within a product – including queries entered, zero-result queries, query reformulations, and search-to-action conversion rates – to discover unmet information needs, user intent vocabulary, failed retrieval patterns, and the gap between how users think about content and how the system organises it. Zero-result queries are particularly high-signal: they are a direct inventory of things users expected to find but could not. Valuable for search-heavy products, internal knowledge tools, documentation systems, e-commerce catalogs, and AI products with query or chat interfaces.","cat":"ana","tier":"ext","r":["V","U"],"s":["E","O"],"eff":"lm","cx":"sm","ts":["solo","sm"],"cs":["any"],"t":"Days to 1-2 weeks","tn":"short","cost":"t0","ev":"str","evtype":"beh","out":"Search analysis report: zero-result query inventory, dominant intent taxonomy with query volumes, reformulation chains, search-to-action conversion by intent, vocabulary gap map, and prioritised gap register with recommended product or content actions.","how":["Access and export query logs – Pull a representative sample: at minimum 2-4 weeks of data, more if volume is low.","Extract zero-result queries – Separate all queries that returned no results.","Cluster queries by intent – Group semantically similar queries together using manual review (low volume) or clustering tools (high volume).","Analyse reformulation chains – Find sessions where a user submitted multiple queries.","Measure search-to-action conversion – For each intent cluster, what percentage of sessions resulted in a click, task completion, or scroll to a result? Low conversion on a high-volume intent is a high-priority gap.","Build the gap inventory – Document: (a) zero-result queries with no content coverage, (b) high-volume queries with low click-through, (c) vocabulary mismatches between users and the system.","Feed into product and content decisions – Map gaps to actions: new content, new features, retrieval improvement, taxonomy change, AI response improvement."],"wtu":["When users are searching and you have logs to analyse","Before redesigning navigation, taxonomy, or information architecture – query data shows what users expect to find regardless of how content is organised","When building or improving an AI query interface, chatbot, or RAG system – zero-result and reformulation patterns directly inform retrieval and coverage gaps","As a complement to user interviews: interviews reveal why users search, logs show what they actually search for"],"wnu":["When search volume is too low for meaningful patterns (fewer than a few hundred queries per analysis window)","As a substitute for understanding user intent – query analysis reveals what users typed, not why; pair with M1 or M7 to understand underlying jobs","When query logs contain unredacted personal data and have not been assessed for GDPR/CCPA compliance"],"kc":"","ai":"AI can cluster large query logs by semantic intent, identify synonyms and vocabulary mismatches between user queries and system vocabulary, surface zero-result patterns at scale, and draft the gap register from raw log data. Significantly reduces manual analysis time for high-volume search logs. Cannot infer user motivation from query strings alone – qualitative follow-up is required.","orig":"Established practice in information architecture and search UX since the late 1990s. Formally described as a product discovery methodology in Rosenfeld (2016). Extended to conversational and AI query interfaces through work on query understanding and conversational information seeking (Zamani et al., 2023).","eu":true,"lt":true,"lr":"conditional","pre":[]},{"id":"M95","n":"Win/Loss Interviews","desc":"Structured retrospective interviews with buyers who chose your product and buyers who chose a competitor or alternative – conducted after a purchase or non-purchase decision has been made. Unlike sales call analysis, which captures observed sales dynamics in real time, win/loss interviews gather reflective causal explanation from decision-makers once the pressure of the sales process is removed. Buyers are more candid after the decision is finalized. The method reveals the actual reasons for buying or not buying – differentiation drivers, competitive perception, pricing sensitivity, trust signals, and deal-breakers – rather than the sales narrative either side presented during the process. A primary viability and commercial discovery method for B2B products and enterprise software.","cat":"gen","tier":"ext","r":["Vi","V"],"s":["E","Va"],"eff":"med","cx":"m","ts":["sm"],"cs":["scale","ent"],"t":"3-6 weeks","tn":"long","cost":"low","ev":"str","evtype":"sr","out":"Win/loss analysis report: key win drivers, key loss drivers, competitive comparison summary, pricing perception, buyer decision criteria ranked by frequency, messaging gaps, and prioritised product or positioning actions.","how":["Define the cohort window – Select a discrete cohort: deals closed (won or lost) in the last 60-90 days.","Identify and recruit participants – Work with sales or CRM to identify contacts.","Design the interview guide – Use a structured but conversational guide.","Conduct interviews – 45-60 minutes per participant.","Code and pattern-analyse findings – Tag responses by: win/loss category, primary decision criterion, competitive comparison mentions, pricing sensitivity signals, and trust/risk factors.","Build the competitive insight report – Summarise: top win drivers, top loss drivers, competitive positioning gaps, pricing perception, and the criteria buyers prioritised that your messaging did or did not address."],"wtu":["When you need to understand why you are winning or losing deals – not based on sales team perception, but based on buyer explanation","Before repricing, repositioning, or changing go-to-market strategy – win/loss data should inform strategic pivots","When competitive differentiation is unclear or contested internally – this method surfaces what buyers actually perceive as differentiation, which often differs from internal assumptions","When product-market fit signals are ambiguous – a pattern of losses for a consistent reason is direct PMF signal"],"wnu":["As a substitute for generative problem discovery (M1, M2) – win/loss is post-decision; it tells you how buyers evaluated, not what job they were trying to do before they started evaluating","When there are no defined sales events – does not apply to self-serve consumer products with no identifiable buy/no-buy moment","When fewer than 8 interviews are feasible – below that threshold, patterns are unreliable and risk over-indexing on outliers","Do not conflate with Sales Call Analysis (M8): that method observes live deal dynamics; this method gathers retrospective buyer explanation after the decision is final"],"kc":"","ai":"AI can assist with interview guide design, transcript analysis, pattern coding across interviews, and generating a structured synthesis report. Particularly useful for surfacing recurring language and competitive mention patterns across a cohort of transcripts. Cannot replace the interviewer's real-time judgment in probing ambiguous responses.","orig":"Established B2B sales improvement practice, systematized as a product and market research methodology by Almquist et al. and applied broadly in SaaS competitive intelligence frameworks. Formally described as a discovery methodology by Chernow (2020) and applied in Pattabhiraman (2018) in the context of product-market fit validation.","eu":false,"lt":false,"lr":false,"pre":[]},{"id":"M96","n":"Comparative Usability Testing","desc":"A structured usability study in which participants complete a defined set of tasks using two or more products – your product and a direct competitor, alternative solution, or incumbent workflow – in a controlled session. Unlike standard usability testing (M16), which focuses on absolute performance of a single product, comparative testing produces relative performance data: which product is faster, less error-prone, or preferred on defined tasks. Unlike Preference Testing (M54), which measures stated preference, comparative usability testing measures task performance – time-on-task, error rate, task success – as well as perceived ease. It is the cleanest method for generating defensible competitive usability evidence and for understanding where users switching from an incumbent experience friction. Particularly relevant for switching products, redesigns, and category-entry decisions.","cat":"eval","tier":"ext","r":["U","V"],"s":["Va"],"eff":"med","cx":"m","ts":["sm"],"cs":["scale","ent"],"t":"2-4 weeks","tn":"med","cost":"low","ev":"str","evtype":"beh","out":"Comparative usability report: per-task completion rates, time-on-task comparison, error rates, SEQ scores by product and task, participant-level observations, qualitative themes from think-aloud, and design priority recommendations based on competitive gaps.","how":["Define the comparison hypothesis – What are you testing? Frame as a specific task-based question: \"Can users complete [task] faster and with fewer errors in our product than in [competitor/incumbent]?\" Name the comparison condition explicitly before designing tasks.","Select tasks – Choose 3-6 tasks that represent the core use cases where the comparison matters.","Recruit participants – Target users who are familiar with at least one of the comparison conditions – ideally current users of the incumbent.","Conduct sessions – 60-90 minutes per participant.","Score and compare – Calculate per-product, per-task means for: task completion rate, time-on-task (geometric mean), error rate, and SEQ score.","Synthesise competitive findings – Identify: tasks where your product is clearly faster or more accurate, tasks where competitor wins, and tasks where switching friction is highest (highest error rate + lowest SEQ on transition tasks)."],"wtu":["When entering a market with an established incumbent – this method directly answers \"can our product displace what users already use?\"","Before a major redesign of a core workflow – test the proposed redesign against the old version, not just in isolation","When competitive differentiation claims are contested – \"easier to use than [competitor]\" is a testable hypothesis","When sales teams report usability objections during deals – comparative data is concrete counter-evidence or a direct improvement mandate"],"wnu":["As a substitute for standard usability testing (M16) – run standard usability testing first to identify baseline issues before adding the comparative complexity","When no comparable incumbent or competitor exists – comparative testing requires a valid comparison condition; testing against a hypothetical baseline is not this method","When the product is in early prototype stage – comparative testing is most valuable when your product is close enough to the comparison condition to be a fair contest; do not run a wireframe against a mature product","Do not conflate with Preference Testing (M54), which measures stated preference; this method measures task performance and may diverge from stated preference"],"kc":"","ai":"AI can assist with task design, session note analysis, pattern synthesis across sessions, and generation of the comparative scoring table and report. Transcript analysis works well for identifying recurring friction points and competitor-specific language. Cannot replace the facilitator's real-time judgment and cannot observe behavioral signals from audio-only transcripts.","orig":"Comparative methodology in usability testing formalised by Nielsen (1993) and extended by Lewis (2012) in ISO 9241-11 standardised measurement frameworks. Competitive benchmarking as a distinct discipline described in Sauro & Lewis (2016). Applied specifically to switching products in the SaaS context through Forrester CX benchmarking methodology.","eu":false,"lt":false,"lr":false,"pre":["M16"]}],"tools":[{"id":"M32","n":"Assumption Mapping","desc":"Systematically identifying, categorizing, and prioritizing the assumptions underlying a product idea. Maps assumptions by importance and uncertainty to focus discovery efforts where they matter most.","cat":"sf","tier":"core","r":["V","U","F","Vi","C"],"kc":"A context tool – it directs which discovery methods to run but does not generate evidence itself. Using Assumption Mapping in place of actual research is Discovery Karaoke; using it to focus your research is exactly the right application.","ai":"AI can generate initial assumption lists from product briefs, identify hidden assumptions the team missed, and suggest experiments for each assumption type.","orig":"Developed in the Lean Startup and design thinking communities. Formalized by David Bland and Alex Osterwalder.","wtu":["Starting any new initiative and you need to focus discovery efforts","Team is debating what to research first (assumption mapping creates clarity)","You want to avoid the \"research everything\" trap and focus on what matters most"],"wnu":["You're past the assumption stage and need to run experiments","The initiative is so small that listing assumptions is overkill","The team isn't willing to honestly assess their own uncertainty (cognitive bias blocks the exercise)"]},{"id":"M33","n":"Opportunity Solution Trees (OST)","desc":"A visual framework connecting desired outcomes to discovered opportunities to potential solutions to experiments. Ensures solutions are grounded in real user opportunities and systematically tested.","cat":"sf","tier":"core","r":["V","Vi","F"],"kc":"A context tool – it structures and visualises the relationships between outcomes, opportunities, and solutions to guide discovery priorities, but does not generate evidence on its own. Its value is in making sure the right methods are run on the right questions.","ai":"AI can help brainstorm solution alternatives for opportunities, suggest experiments, and identify gaps in the tree where more research is needed.","orig":"Developed by Teresa Torres as part of the Continuous Discovery Habits framework.","wtu":["You want to establish a continuous discovery practice (not just one-off research)","The team needs a structured way to connect user research to product decisions","You have multiple possible solutions and need to systematically compare them"],"wnu":["You're doing a one-time research project, not continuous discovery","The problem is so simple that a tree is unnecessary overhead","The team isn't doing regular user research to feed opportunities into the tree"]},{"id":"M35","n":"Customer Journey Mapping","desc":"Visualizing the complete end-to-end experience a customer has with your product/service, including touchpoints, emotions, pain points, and moments of truth. Reveals the holistic experience across channels and over time.","cat":"syn","tier":"ext","r":["V","U"],"kc":"A context tool – Customer Journey Maps synthesise and communicate existing research. They do not generate new evidence. A journey map built without prior user research is organisational fiction. Use after generative research (M1, M3, M4) to structure what you learned, then use the gaps to plan further discovery.","ai":"AI can help draft journey maps from research data, identify emotional patterns from interview transcripts, and suggest common touchpoints for your industry.","orig":"Roots in service design (Lynn Shostack, 1984, \"Designing Services That Deliver\"). Popularized in UX by Adaptive Path (now part of Capital One) and Nielsen Norman Group.","wtu":["You need to understand the end-to-end customer experience across touchpoints","Silos in your organization are creating fragmented experiences","You want to identify the highest-impact improvement opportunities across the journey"],"wnu":["You're mapping based on assumptions, not research","The journey is simple and well-understood","You need to optimize a single interaction, not the overall journey"]},{"id":"M36","n":"Service Blueprinting","desc":"An extension of journey mapping that includes the organization's internal processes, systems, and roles that support the customer experience. Shows the frontstage (what users see) and backstage (what enables it) together.","cat":"syn","tier":"ext","r":["F","U","C","V"],"kc":"A context tool – Service Blueprinting maps service delivery processes (front and back stage) to reveal gaps and failure points. It requires existing knowledge of the service to be accurate and does not generate evidence on its own. Use it to focus feasibility and compliance discovery on the right system points.","ai":"AI can help draft initial blueprints from process documentation and identify potential failure points based on common service design patterns.","orig":"Developed by G. Lynn Shostack (1984, \"Designing Services That Deliver,\" Harvard Business Review). Extended by Mary Jo Bitner et al.","wtu":["Your service involves complex internal operations that affect customer experience","You need to redesign a service end-to-end (not just the UI)","Compliance or regulatory processes are intertwined with the customer experience"],"wnu":["You're only redesigning a digital interface with no service operations behind it","The service is simple enough that a journey map covers it","You can't get participation from operations, engineering, and support teams"]},{"id":"M37","n":"Empathy Mapping","desc":"A structured visual template capturing what a user says, thinks, does, and feels about a topic or experience. Creates shared empathy within the team and surfaces contradictions between stated and actual behavior.","cat":"syn","tier":"ext","r":["V"],"kc":"A context tool – Empathy Maps synthesise and communicate what the team knows (or assumes) about users' thoughts, feelings, and actions. They do not generate new evidence. A map filled with team assumptions instead of research data is a projection exercise, not an empathy exercise. Use after real research; use gaps to plan further discovery.","ai":"AI can pre-populate empathy maps from interview transcripts, grouping quotes into the four quadrants for team review and refinement.","orig":"Developed by Dave Gray at XPLANE (now Dachis Group). Published in Gamestorming (2010).","wtu":["You've done user research and want to build team-wide empathy","You're starting a design workshop and need to align the team on user perspective","You want a quick synthesis activity to organize interview data"],"wnu":["You're filling it in from assumptions, not research","You're using it as a substitute for actual user research","The team has strong user empathy already and this would be redundant"]},{"id":"M38","n":"Persona Development","desc":"Creating fictional but research-based character profiles representing key user segments. Includes demographics, goals, behaviors, pain points, and context. Used as a shared reference point for product decisions.","cat":"syn","tier":"ext","r":["V","U"],"kc":"A context tool – Personas synthesise prior research into representative archetypes to align the team on who they're building for. They do not generate new evidence. Personas built from demographics and assumptions are corporate horoscopes. Use after generative research; their value depends entirely on the quality of the underlying research.","ai":"AI can draft persona profiles from research data, suggest behavioral attributes, and identify gaps in persona coverage across user segments.","orig":"Developed by Alan Cooper in The Inmates Are Running the Asylum (1999). Extended by Kim Goodwin and John Pruitt.","wtu":["The team lacks a shared understanding of who they're building for","Product decisions are driven by stakeholder opinions instead of user needs","You need to communicate user research findings in an accessible, memorable format"],"wnu":["Personas are based on assumptions, not research","The team already has strong, research-backed user understanding","You're creating personas as a deliverable that no one will reference"]},{"id":"M39","n":"Value Proposition Canvas","desc":"A structured tool for designing products that match customer needs. Maps customer jobs, pains, and gains on one side, and product features, pain relievers, and gain creators on the other. Helps teams articulate and test value-fit hypotheses before committing to a direction.","cat":"sf","tier":"ext","r":["V","Vi"],"kc":"A context tool – the Value Proposition Canvas maps the fit between customer jobs/pains/gains and your product's features/pain relievers/gain creators. It is a synthesis and alignment tool, not an evidence-generation method. Its assumptions must be tested with methods from the Evaluative and Experimentation categories.","ai":"AI can suggest customer jobs/pains/gains from market research data and identify potential value proposition gaps.","orig":"Alexander Osterwalder and Yves Pigneur, as an extension of the Business Model Canvas.","wtu":["You're defining or refining your product's value proposition","You need to align product features with validated customer needs","You're evaluating multiple value proposition options"],"wnu":["You haven't done customer research (filling from assumptions = fiction)","The value proposition is well-established and you're optimizing, not rethinking","You're using it as a one-time exercise without follow-up validation"]},{"id":"M42","n":"Competitive Analysis","desc":"Systematic evaluation of competitors' products, positioning, features, pricing, and strategies. Identifies market gaps, differentiation opportunities, and standard expectations. Not about copying—about understanding the landscape.","cat":"sf","tier":"ext","r":["Vi"],"kc":"Competitive Analysis maps the existing landscape – it generates evidence about the market and competitors, but does not generate evidence about your own users' needs or your product's fit. Use it to calibrate discovery scope and set realistic benchmarks; follow with methods that test your own product's assumptions.","ai":"AI can scrape and summarize competitor websites, analyze review platforms at scale, and identify feature patterns across competitors.","orig":"Michael Porter's competitive strategy framework (1980). Adapted extensively in product management.","wtu":["You're entering a new market or launching a new product","You need to justify differentiation to stakeholders or investors","You haven't refreshed competitive intelligence in 6+ months"],"wnu":["You're using it to copy competitors rather than differentiate from them","You're in a genuinely new category with no direct competition","Analysis paralysis: spending weeks comparing when you should be testing with users"]},{"id":"M64","n":"Pre-mortem (Prospective Hindsight)","desc":"A structured exercise where the team imagines the product or initiative has already FAILED, then works backward to identify the most likely causes. Uses prospective hindsight (imagining a future outcome as certain) to surface risks and blind spots that forward-looking planning misses.","cat":"col","tier":"ext","r":["V","U","F","Vi","C"],"kc":"A context tool – Pre-mortems surface assumptions and risks by imagining failure before it happens. They generate a structured list of hypotheses worth testing, not evidence. Use it to populate an Assumption Map (M32) and prioritise which discovery methods to run next.","ai":"AI can generate additional failure scenarios from comparable products/markets, and help identify risks the team may have missed. Useful as a \"10th team member\" providing outside-view risks.","orig":"Gary Klein (1998), based on research by Deborah Mitchell, Jay Russo, and Nancy Pennington (1989) showing that prospective hindsight – imagining an event has already occurred – increases the ability to identify reasons for the outcome by approximately 30% in that specific study. The precise uplift figure is from one experimental context; the core practice is well-supported but the exact number should not be treated as a universal benchmark.","wtu":["Before making a significant investment decision (new product, major feature, pivot)","When the team seems overconfident or has collective blind spots","At the start of a discovery cycle to identify what risks to investigate first","When stakeholders are pushing to skip discovery (\"just build it\")"],"wnu":["As a substitute for actual discovery (pre-mortem identifies risks; you still need methods to investigate them)","When the team culture punishes negative thinking (the exercise will be performative, not honest)","For small, easily reversible decisions (overkill)"]},{"id":"M88","n":"JTBD Framework (Forces of Progress)","desc":"The conceptual and analytical framework underlying Jobs-to-be-Done: users \"hire\" and \"fire\" products when trying to make progress in a specific context. The Four Forces diagram maps why people switch – Push (frustration with current situation) and Pull (attraction to new solution) drive switching, while Habit and Anxiety resist it. Applied after JTBD Interviews (M2) to synthesise switching forces data into a structured model that explains adoption and churn better than demographics or stated preferences.","cat":"sf","tier":"ext","r":["V"],"kc":"A context tool – the JTBD Forces of Progress framework reframes user behaviour as a set of forces (push, pull, anxiety, habit) driving or blocking adoption decisions. It is a theoretical lens for designing better interview questions and interpreting data, not a standalone evidence-generation method. Use it to sharpen M1/M2 interview design and analysis.","ai":"Analyze interview transcripts for language patterns that map to the four forces, suggest force categorizations for researcher validation, and identify which forces appear strongest across a set of switcher interviews. Cannot infer the forces without real JTBD interview data – the framework requires real switcher stories to be meaningful.","orig":"Conceptual foundation by Clayton Christensen (Harvard Business School) in Competing Against Luck (2016). Four Forces model and Switch Interview methodology developed by Bob Moesta and Chris Spiek (The Re-Wired Group). Distinguished from the interview method (M2) – this is the analytical framework for interpreting the interview data.","wtu":["After M2 (JTBD Interviews) to synthesise switching forces data into a structured model","When the team is trying to understand why users switch to or away from the product","When demographic segmentation is not predictive and behavioral/job-based segmentation is needed","When innovation is stalling because the team is focused on features rather than the progress users are trying to make"],"wnu":["For incremental optimization of a well-understood product (analytics and A/B testing are faster)","When no JTBD interviews have been conducted – the framework requires real switcher data to populate; assumptions produce the wrong jobs","As a one-time workshop exercise rather than an ongoing analytical lens"]},{"id":"M89","n":"Capability Contract Workshop","desc":"A structured workshop to define the explicit boundaries of an AI system before committing to build – specifying what it is Allowed to do, Forbidden from doing, what Evidence it must provide, what data it can Retrieve, how it Escalates out-of-scope requests, and a Version identifier. Running the Contract during Explore surfaces feasibility blockers, data permission gaps, and compliance constraints that no amount of user research can reveal. **Author-originated framework** (Amodiovalerio Verde / The Thinking Lens, 2026) – not an established external method; included because it addresses a real gap in AI product discovery practice.","cat":"sf","tier":"ext","r":["F","C"],"kc":"A context tool – the Capability Contract does not generate user evidence. It generates a scoping specification that reveals where feasibility, data, and compliance risks live. Use it to direct which discovery methods to run next: gaps in Retrieval Scope → Data Readiness Assessment (M91); gaps in Forbidden/Evidence → DPIA (M76) or Privacy Threat Modeling (M77).","ai":"AI can draft an initial Contract from a feature brief – proposing common Allowed/Forbidden patterns for similar AI feature types, flagging retrieval scope conflicts, and identifying gaps in Evidence requirements. The workshop remains essential: the team validates, adjusts, and signs off. AI drafts the v0; humans own the v1.","orig":"Proposed by Amodiovalerio Verde (2026) as Station 1 of the Semantic Supply Chain framework, developed from enterprise AI deployment practice. Formalises a scoping discipline that emerged from observing AI projects fail due to undefined system boundaries – not from academic literature. The framework treats AI capabilities like API contracts: versioned, explicit, enforceable.","wtu":["At the start of any AI feature development, before architecture decisions are made","When integrating AI into regulated or high-stakes workflows","When the team is not aligned on what the AI \"is\" and \"isn't\"","Before security or compliance review – the Contract is the input document","When evaluating whether to build vs buy vs integrate an AI capability"],"wnu":["For pure UI features with no AI judgment, generation, or autonomous action","When the AI feature is fully standardised with no customisation (e.g., commodity spell-check)","As a substitute for legal review – the Contract is a discovery tool; formal legal assessment is separate (M76, M84)"]}],"patterns":[{"n":"The Interview Reflex","pat":"We need to understand this better → Let's do user interviews","signs":["Every discovery effort starts with interviews regardless of the question type","You interview ten or more users but still cannot make a decision","Interview findings confirm what the team already believed before starting","Interviews are scheduled before the team can articulate what specific uncertainty they are trying to resolve","You are exploring when you should be validating, or validating when you should be measuring","Participants are exclusively internal users, colleagues, or the same recurring small panel"],"rec":["Do I need to understand the problem or test a solution?","Could existing behavioral data — analytics, support tickets, sales calls — answer this faster?","Am I looking for patterns or measuring something I already know exists?","Am I interviewing because it reduces uncertainty, or because it feels thorough?"],"risk":"V"},{"n":"The Design Sprint Default","pat":"We have a big question → Let's run a design sprint","signs":["Design sprints are scheduled for every new initiative as the default \"big question\" response","Most sprint time is spent aligning on the problem, not testing solutions","The likely prototype could be described before the sprint starts","Sprint results rarely change the planned direction","You finish the sprint and immediately run the same research you would have run anyway"],"rec":["Could a two-hour M32 (Assumption Mapping) session surface the real question without five days of coordination?","Is the problem clear enough that the team just needs to test solutions?","Is the real need alignment, not discovery?","What specific evidence would the sprint Friday test produce — and could we get that evidence faster?"],"risk":"V"},{"n":"The Extended Beta","pat":"We're not sure about this → Let's run a three-month beta","signs":["The beta keeps extending because results are \"inconclusive\"","The team cannot articulate what specific evidence would make this a go or a no-go","Beta users are not representative of the target market","\"Beta\" is being used to launch something without committing to it","No success criteria were defined before the beta started"],"rec":["What specific metric would make this a go/no-go? Write it down before the beta starts","Is this testing value (do they want it?) or usability (can they use it?) or reliability (does it hold at scale)? Each needs a different method","Could M26 (Concierge MVP) answer the demand question in two weeks instead of three months?","If the beta ended today with current data, what would the decision be?"],"risk":"V"},{"n":"The Survey Spray","pat":"We need data → Let's send a survey","signs":["Survey questions are leading, double-barreled, or assume knowledge the respondent may not have","The survey was launched before any qualitative work established what to ask","Response rates are low and the team does not investigate why","Results are ambiguous — the team cannot make a decision from them","The survey was chosen because it is cheap and easy, not because it is the right tool"],"rec":["Do I know enough to write good survey questions? If not, run M1 or M3 first","Am I measuring a pattern I already understand or trying to discover patterns I do not?","Could behavioral analytics — M56 (Funnel Analysis), M57 (Feature Audit), M55 (Cohort Analysis) — answer this without recruiting participants?","What decision will I make based on the results, and will the survey actually produce data precise enough to make it?"],"risk":"V"},{"n":"The Prototype Trap","pat":"We should build a prototype to test this","signs":["Weeks are spent on high-fidelity prototypes before any demand validation has occurred","Prototype tests show users \"like it\" but no one knows whether they would pay or use it without prompting","The team is prototyping features that could be A/B tested on the live product","The prototype is being built because designers feel productive building it, not because it answers a specific question"],"rec":["Am I testing usability or value?","What fidelity do I actually need? Could a paper sketch (M28) or M15 (Five-Second Test) answer the same question at a tenth of the cost?","Could I test this on the live product instead of building a prototype?","Would a M26 (Concierge MVP) or M48 (Pre-sales/LOI) tell me more about demand than any prototype?"],"risk":"U"},{"n":"The Research Procrastination","pat":"We need to do more research before we can decide","signs":["The team cannot name the specific risk or assumption being tested","Research findings keep raising new questions rather than answering existing ones","Stakeholders use \"we need more research\" to avoid making a decision that is already supported by existing evidence","The research backlog grows faster than the insights that come from it","No one can describe what evidence would make the team confident enough to move"],"rec":["What specific assumption or question would this research answer?","What would we do differently based on the answer? If nothing, do not do the research","Is the cost of being wrong higher than the cost of this research?","Could we learn faster by shipping something small and measuring the response?","Have we run M32 (Assumption Mapping) to rank which uncertainty is actually the most expensive to leave unresolved?"],"risk":"V"},{"n":"The Analytics Anchor","pat":"The data shows X, so we know what to do","signs":["Discovery consists almost entirely of reviewing dashboards and usage data","Qualitative research has not been conducted in over six months","Declining metrics trigger more measurement, not user contact","The team can describe what users do in the product but cannot describe why they use it or what job it does for them","No one has talked to a churned user or a lost prospect in recent memory"],"rec":["Do we understand the why behind the behavioral pattern, or just the what?","When did we last run M1 (User Interviews) or M92 (Churn and Lost Customer Interviews) to understand what users are actually trying to accomplish?","Are we optimizing a feature that users are using because it is the only option, not because it is good?","What would M3 (Contextual Inquiry) or M66 (Shadowing) show us that no dashboard can?"],"risk":"V"},{"n":"The Stakeholder Appeasement","pat":"The VP wants user research, so let's do a study","signs":["The research question was set by someone who will not use the findings","The team knows the \"right answer\" before the study starts","Findings are presented and acknowledged but nothing changes afterward","Research is timed to coincide with a decision that has already been made","The study was scoped to validate a direction, not to test it"],"rec":["Who will use these findings, and what specific decision are they facing?","What would the team do differently if the findings were surprising?","Is the real need alignment rather than evidence?","Could a M64 (Pre-mortem) surface the real concern faster than a research study?"],"risk":"V"},{"n":"The Validation Theater","pat":"Let's do some research to support this direction","signs":["Interview guides contain leading questions that point toward the desired answer","The team cannot name the specific finding that would make them stop or change direction","Discovery findings never surprise anyone — they consistently confirm what the team already believed before starting","Positive quotes are highlighted in decks; contradicting feedback is filed as \"edge cases\" or \"not our target user\"","Experiments are scoped to UI variations rather than testing whether the core value proposition holds","The \"hypothesis\" is written after results come in, not before"],"rec":["What specific finding would make us kill this bet or change direction? If you cannot name it, the research is not designed to reduce uncertainty","Have we written our evidence threshold before the research starts — not after?","Are we testing this assumption, or are we proving it? If we already know the answer, run M32 to find what we genuinely do not know","Could we design a test that produces a clear no-go signal if the assumption is wrong?","Have we asked someone outside the team to review the discussion guide before running it?"],"risk":"V"},{"n":"The AI Shortcut","pat":"Let's use AI to simulate the user feedback","signs":["AI-generated \"user quotes\" appear in research decks without a SYNTHETIC label","The team skips qualitative research because \"the AI already told us what users think\"","Synthetic personas are used in place of research-based personas","No one can trace an insight back to a real user interaction, session, or data source","AI outputs are used to justify a go/no-go decision"],"rec":["Would we make this decision based on what a model predicts, or what a real user demonstrates?","Have we validated any AI-generated hypotheses with at least two to three real user data points?","If we removed all AI-generated content from our research, what real evidence remains?","Is AI being used to prepare for real research or to replace it?"],"risk":"C"},{"n":"The Compliance Afterthought","pat":"We'll do a legal review before launch","signs":["Compliance is owned exclusively by legal or a separate compliance function, not by the product team","The first compliance check happens after design is complete","Accessibility (M19) and privacy (M76) are treated as nice-to-haves rather than launch requirements","No one has run a data-flow map (M75) before designing data-handling features","For AI products: M89 (Capability Contract Workshop), M90 (AI Capability Assessment), and M91 (Data Readiness Assessment) are not part of the Explore phase","The team has never asked: \"Who could be harmed by this product, even if they are not our target users?\""],"rec":["What is the compliance risk category for this feature? Run M75 (Data-flow Mapping) and M84 (Legitimate Interests Assessment) as a lightweight triage before design starts","Is processing likely to create high risk to individuals — for example, large-scale profiling, automated decision-making, or processing of sensitive categories of data? If yes, M76 (DPIA/PIA) is legally required under GDPR and good practice under most equivalent frameworks. For major new personal-data projects more broadly, starting a DPIA early rather than as a pre-launch gate is the ICO's documented recommendation","For AI products: have M89, M90, and M91 run in sequence at the Explore stage?","Would we be comfortable if our discovery process and decisions — including what we chose not to test — were made public?","What happens if this feature works exactly as designed but at 100x the current scale?"],"risk":"Vi"},{"n":"The Viability Skip","pat":"Users love it — let's build it","signs":["Discovery covers Value and Usability thoroughly but rarely touches pricing, willingness to pay, or commercial validation","No one has run M48 (Pre-sales/LOI), M93 (Pricing and Willingness-to-Pay Testing), or M69 (Conjoint Analysis) before committing to build","For B2B products: sales team opinion is being used as a proxy for buyer insight instead of M95 (Win/Loss Interviews) or M92 (Churn and Lost Customer Interviews)","Cohort data (M55) shows poor retention but no one has investigated why","The team can describe what users want but cannot describe what they would pay, or what it would take to make them switch"],"rec":["Could a user love this but not pay for it? Have we tested willingness to pay with M93 or M69 rather than just asking?","For B2B: are we using sales team perception of why we win and lose deals, or actual buyer explanation?","Have we run M48 (Pre-sales/LOI) or M67 (Sales-Led Prototype Testing) to get real commercial commitment before investing in build?","Do we understand why users churn or why prospects chose a competitor?","Are we validating the product or the business model? Both need evidence"],"risk":"V"},{"n":"The Static Playbook","pat":"Having a fixed \"discovery process\" that every initiative follows.","signs":[],"rec":["The process becomes the default regardless of risk type, stage, or context. Teams follow the steps instead of following the uncertainty. The method becomes the goal; the question gets lost. The deeper"],"risk":"V"}],"diag":[{"q":"We use the same 2-3 discovery methods for most initiatives regardless of the question","pat":"The Static Playbook"},{"q":"Our discovery process is the same regardless of risk type or stage","pat":"The Static Playbook"},{"q":"We cannot name the specific finding that would make us stop or change direction on a current bet","pat":"The Interview Reflex"},{"q":"We default to interviews when we are unsure what to do","pat":"The Interview Reflex"},{"q":"We use AI-generated insights as research evidence without validating them against real user data","pat":"The Research Procrastination"},{"q":"We treat compliance and ethics as a final gate rather than a first-class discovery input","pat":"The Compliance Afterthought"},{"q":"We do not adjust evidence thresholds based on bet size","pat":"The Research Procrastination"},{"q":"Our discovery is mainly about building confidence, not reducing uncertainty","pat":"The Stakeholder Appeasement"},{"q":"We rely primarily on analytics without regular qualitative research","pat":"The Analytics Anchor"},{"q":"We have not spoken to a churned user or a lost prospect in the past three months","pat":"The Viability Skip"},{"q":"We build prototypes or MVPs before validating that we understand the underlying problem","pat":"The Prototype Trap"},{"q":"We continue researching after we already have enough signal to make a decision","pat":"The Validation Theater"}],"matrix":{"V":{"E":["M1","M2","M8"],"Va":["M23","M47","M48"],"O":["M20","M55","M56"]},"U":{"E":["M3","M66"],"Va":["M16","M17","M18"],"O":["M58","M59","M20"]},"F":{"E":["M9","M89","M91"],"Va":["M44","M45","M26"],"O":["M68","M72"]},"Vi":{"E":["M8","M9","M42"],"Va":["M48","M24","M67"],"O":["M55","M56","M20"]},"C":{"E":["M75","M76","M9"],"Va":["M19","M81","M80"],"O":["M82","M57","M80"]}},"meta":{"v":"2.1","gen":"2026-04-16","m":69,"t":11,"p":13}};
